import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { TabType, Device, HistoryEntry, AssetStatus, User } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import UsersView from './components/UsersView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';
import AddUserModal from './components/AddUserModal';
import AssignUserModal from './components/AssignUserModal';
import EditDeviceModal from './components/EditDeviceModal';
import IdentificationView from './components/IdentificationView';

const DEVICES_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=0&single=true&output=csv';
const USERS_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=1789914936&single=true&output=csv';
const HISTORY_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vSPQVVjmPXRJE3w0PhujorFo-Uj8mVwJ4Aa20i6LmsZpgmk-3pUsqajXf8Bhm68XXnROzierh4SITQ5/pub?gid=801829903&single=true&output=csv';
const GOOGLE_SCRIPT_APP_URL = 'https://script.google.com/macros/s/AKfycbywRpgG-YElFth55EkcjLYQgH4bepTf_yMYsVI9X2ktgf9hABt6sxxa-D7Tj2ySf7Q1/exec';

const parseCSV = (csvText: string): any[] => {
  const lines = csvText.split(/\r?\n/);
  if (lines.length < 2) return [];
  const headers = lines[0].split(',').map(h => 
    h.replace(/"/g, '').trim().toLowerCase().replace(/\s+/g, '')
  );

  return lines.slice(1).filter(line => line.trim() !== '').map(line => {
    const values: string[] = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      let char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') { current += '"'; i++; }
        else { inQuotes = !inQuotes; }
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else { current += char; }
    }
    values.push(current.trim());
    return headers.reduce((obj: any, header, i) => {
      let val = values[i] || '';
      val = val.replace(/^"|"$/g, '');
      obj[header] = val;
      return obj;
    }, {});
  });
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [isAddDeviceOpen, setIsAddDeviceOpen] = useState(false);
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [assigningDevice, setAssigningDevice] = useState<Device | null>(null);
  const [editingDevice, setEditingDevice] = useState<Device | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isAdmin = currentUser?.role === 'ADMIN';

  const visibleDevices = useMemo(() => {
    if (!currentUser) return [];
    if (isAdmin) return devices;
    return devices.filter(d => 
      d.assignedTo === currentUser.name || 
      d.assignedTo === currentUser.employeeId
    );
  }, [devices, currentUser, isAdmin]);

  const visibleHistory = useMemo(() => {
    if (!currentUser) return [];
    if (isAdmin) return history;
    const deviceIds = new Set(visibleDevices.map(d => d.tagId));
    return history.filter(h => 
      deviceIds.has(h.deviceId) || 
      h.target === currentUser.name || 
      h.target === currentUser.employeeId
    );
  }, [history, visibleDevices, currentUser, isAdmin]);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const cb = `cb=${Date.now()}`;
      const [devicesRes, usersRes, historyRes] = await Promise.all([
        fetch(`${DEVICES_CSV_URL}&${cb}`),
        fetch(`${USERS_CSV_URL}&${cb}`),
        fetch(`${HISTORY_CSV_URL}&${cb}`)
      ]);

      if (!devicesRes.ok || !usersRes.ok) throw new Error("Không thể tải dữ liệu.");

      const devicesCsv = await devicesRes.text();
      const usersCsv = await usersRes.text();
      const historyCsv = await (historyRes.ok ? historyRes.text() : Promise.resolve(''));

      const rawDevices = parseCSV(devicesCsv);
      const rawUsers = parseCSV(usersCsv);
      const rawHistory = parseCSV(historyCsv);

      const formattedDevices: Device[] = rawDevices.map((d, index) => ({
        id: d.id || `dev-${index}`,
        tagId: d.tagid || d.tag_id || d.mataisan || d['mãtài sản'] || 'N/A',
        name: d.name || d.ten || d['tên'] || 'Không tên',
        type: d.type || d.loai || d['loại'] || 'Khác',
        location: d.location || d.vitri || d['vịtrí'] || 'Chưa rõ',
        configuration: d.configuration || d.cauhinh || d['cấuhình'] || '',
        status: (d.status?.toUpperCase() as AssetStatus) || 'AVAILABLE',
        assignedTo: d.assignedto || d.nguoisudung || d['ngườisửdụng'] || undefined,
        lastUpdated: d.lastupdated || new Date().toISOString()
      }));
      setDevices(formattedDevices);

      const formattedUsers: User[] = rawUsers.map((u, index) => ({
        id: u.id || `user-${index}`,
        name: u.name || u.ten || u['tên'] || 'Unknown User',
        employeeId: u.employeeid || u.manhanvien || u['mãnhânviên'] || 'N/A',
        role: (u.role?.toUpperCase() === 'ADMIN' ? 'ADMIN' : 'STAFF') as any,
        avatarUrl: u.avatarurl || undefined
      }));
      setUsers(formattedUsers);

      const formattedHistory: HistoryEntry[] = rawHistory.map((h, index) => {
        const device = formattedDevices.find(d => d.tagId === h.tagid);
        let normalizedAction: HistoryEntry['action'] = 'UPDATE';
        const rawAction = h.action?.toUpperCase() || '';
        if (rawAction.includes('ASSIGN')) normalizedAction = 'ASSIGN';
        else if (rawAction.includes('RETURN')) normalizedAction = 'RETURN';
        else if (rawAction.includes('REPAIR')) normalizedAction = 'REPAIR';

        return {
          id: h.id || `hist-${index}`,
          deviceId: h.tagid || 'N/A',
          deviceName: device ? device.name : (h.devicename || h.name || 'Device #' + (h.tagid || index)),
          action: normalizedAction,
          timestamp: h.timestamp ? new Date(h.timestamp).toLocaleString('vi-VN', {
            hour: '2-digit',
            minute: '2-digit',
            day: '2-digit',
            month: '2-digit',
            year: 'numeric'
          }) : 'Unknown Time',
          performer: h.performedby || h.performer || 'Hệ thống',
          target: h.targetuser || h.target || (normalizedAction === 'RETURN' ? 'Kho' : '')
        };
      });

      setHistory(formattedHistory.reverse());

    } catch (err: any) {
      console.error("Fetch Error:", err);
      setError("Lỗi kết nối dữ liệu. Vui lòng kiểm tra quyền truy cập Sheet.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleIdentify = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleDashboardSearch = (val: string) => {
    setSearchTerm(val);
    setActiveTab('devices');
  };

  const handleAddDevice = async (newDevice: Omit<Device, 'id' | 'status' | 'lastUpdated'>) => {
    if (!isAdmin) return;
    setIsSaving(true);
    try {
      const payload = { ...newDevice, action: 'ADD_DEVICE', timestamp: new Date().toISOString() };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });
      setTimeout(() => {
        setIsSaving(false);
        setIsAddDeviceOpen(false);
        fetchData();
        alert("Thiết bị mới đã được lưu!");
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleEditDevice = async (updatedDevice: Device) => {
    if (!isAdmin) return;
    setIsSaving(true);
    const previousDevices = [...devices];
    setDevices(prev => prev.map(d => d.id === updatedDevice.id ? updatedDevice : d));

    try {
      const payload = { 
        ...updatedDevice, 
        action: 'EDIT_DEVICE', 
        tagid: updatedDevice.tagId,
        mataisan: updatedDevice.tagId,
        timestamp: new Date().toISOString(),
        performedBy: currentUser?.name
      };

      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(payload)
      });

      setTimeout(() => {
        setIsSaving(false);
        setEditingDevice(null);
        fetchData();
      }, 2500);

    } catch (err) {
      console.error("Lỗi cập nhật:", err);
      setIsSaving(false);
      setDevices(previousDevices);
    }
  };

  const handleAddUser = async (newUser: Omit<User, 'id' | 'avatarUrl'>) => {
    if (!isAdmin) return;
    setIsSaving(true);
    try {
      const payload = { ...newUser, action: 'ADD_USER', timestamp: new Date().toISOString() };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });

      setTimeout(() => {
        setIsSaving(false);
        setIsAddUserOpen(false);
        fetchData();
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAssignUser = async (user: User) => {
    if (!assigningDevice || !isAdmin || !currentUser) return;
    setIsSaving(true);
    const timestamp = new Date().toISOString();
    try {
      const payload = {
        action: 'ASSIGN_DEVICE',
        deviceId: assigningDevice.id,
        tagId: assigningDevice.tagId,
        tagid: assigningDevice.tagId,
        mataisan: assigningDevice.tagId,
        userId: user.id,
        userName: user.name,
        deviceName: assigningDevice.name,
        timestamp: timestamp,
        performedBy: currentUser.name
      };
      await fetch(GOOGLE_SCRIPT_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload)
      });

      setTimeout(() => {
        setIsSaving(false);
        setAssigningDevice(null);
        fetchData();
      }, 2000);
    } catch (err) {
      console.error(err);
      setIsSaving(false);
    }
  };

  const handleAction = async (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    if (!isAdmin || !currentUser) return;
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;

    if (action === 'ASSIGN') {
      setAssigningDevice(device);
    } else {
      setIsSaving(true);
      const timestamp = new Date().toISOString();
      try {
        const payload = {
          action: 'RETURN_DEVICE',
          deviceId: deviceId,
          tagId: device.tagId,
          tagid: device.tagId,
          mataisan: device.tagId,
          deviceName: device.name,
          timestamp: timestamp,
          performedBy: currentUser.name
        };
        await fetch(GOOGLE_SCRIPT_APP_URL, {
          method: 'POST',
          mode: 'no-cors',
          headers: { 'Content-Type': 'text/plain' },
          body: JSON.stringify(payload)
        });

        setTimeout(() => {
          setIsSaving(false);
          fetchData();
        }, 2000);
      } catch (err) {
        console.error(err);
        setIsSaving(false);
      }
    }
  };

  const handleFabClick = () => {
    if (!isAdmin) return;
    if (activeTab === 'users') setIsAddUserOpen(true);
    else setIsAddDeviceOpen(true);
  };

  if (!currentUser) {
    return <IdentificationView users={users} onSelect={handleIdentify} isLoading={isLoading} />;
  }

  return (
    <div className="flex flex-col min-h-screen pb-20 bg-background">
      <header className="sticky top-0 z-30 flex items-center justify-between px-4 h-16 bg-white border-b border-slate-200">
        <div className="flex items-center gap-2">
          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center shadow-lg shadow-primary/20">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-slate-800 tracking-tight leading-none">AssetFlow</span>
            <span className={`text-[9px] font-bold uppercase mt-0.5 tracking-wider ${isAdmin ? 'text-primary' : 'text-slate-400'}`}>
              {currentUser.role} {isAdmin ? '' : '- VIEW ONLY'}
            </span>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100">
            <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-12">
        {error && (
          <div className="bg-red-50 border border-red-100 text-red-600 p-4 rounded-2xl mb-6 text-sm flex items-center gap-3">
            <span className="material-symbols-outlined">error</span>
            {error}
          </div>
        )}

        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-64 space-y-4">
            <div className="w-10 h-10 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
            <p className="text-sm text-slate-400 font-medium">Đang tải dữ liệu...</p>
          </div>
        ) : (
          <>
            {activeTab === 'dashboard' && (
              <DashboardView 
                devices={visibleDevices} 
                history={visibleHistory} 
                onViewAll={() => setActiveTab('devices')} 
                onAction={handleAction} 
                onEdit={setEditingDevice} 
                isAdmin={isAdmin}
                onSearch={handleDashboardSearch}
              />
            )}
            {activeTab === 'devices' && (
              <DevicesView 
                devices={visibleDevices} 
                onAction={handleAction} 
                onEdit={setEditingDevice} 
                isAdmin={isAdmin}
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
              />
            )}
            {activeTab === 'users' && <UsersView users={users} />}
            {activeTab === 'settings' && (
              <div className="flex flex-col items-center justify-center h-full pt-10 space-y-6">
                <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-xl w-full max-w-sm text-center transform transition-all hover:scale-[1.02]">
                   <div className="w-24 h-24 bg-primary/5 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-white shadow-inner relative">
                      {currentUser.avatarUrl ? (
                         <img src={currentUser.avatarUrl} className="w-full h-full object-cover rounded-full" />
                      ) : (
                         <span className="material-symbols-outlined text-primary text-5xl">person</span>
                      )}
                      <div className={`absolute bottom-0 right-0 w-6 h-6 rounded-full border-4 border-white shadow-sm ${isAdmin ? 'bg-green-500' : 'bg-slate-300'}`}></div>
                   </div>
                   <h3 className="text-xl font-bold text-slate-800 mb-1">{currentUser.name}</h3>
                   <p className="text-sm text-slate-400 font-medium mb-6">Mã nhân viên: {currentUser.employeeId}</p>

                   <div className="flex flex-col gap-3">
                      <div className={`px-4 py-2 text-white text-[11px] font-bold rounded-2xl uppercase tracking-[0.2em] shadow-lg ${isAdmin ? 'bg-primary shadow-primary/20' : 'bg-slate-400'}`}>
                         {currentUser.role} MODE
                      </div>

                      <button 
                         onClick={handleLogout}
                         className="mt-6 flex items-center justify-center gap-2 w-full py-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold text-sm hover:bg-red-50 hover:text-red-500 hover:border-red-100 transition-all active:scale-95"
                      >
                         <span className="material-symbols-outlined text-[20px]">logout</span>
                         Đăng xuất tài khoản
                      </button>
                   </div>
                </div>

                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">AssetFlow v2.4.0</p>
              </div>
            )}
          </>
        )}
      </main>

      {isAdmin && activeTab !== 'settings' && activeTab !== 'dashboard' && (
        <div className="fixed bottom-24 right-6 z-40">
          <button 
            onClick={handleFabClick} 
            className="w-14 h-14 rounded-full shadow-fab bg-primary text-white flex items-center justify-center hover:scale-110 active:scale-95 transition-all"
          >
            <span className="material-symbols-outlined text-[32px]">add</span>
          </button>
        </div>
      )}

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />

      {isAddDeviceOpen && <AddDeviceModal onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {isAddUserOpen && <AddUserModal onClose={() => setIsAddUserOpen(false)} onSubmit={handleAddUser} isSaving={isSaving} />}
      {assigningDevice && <AssignUserModal users={users} onClose={() => setAssigningDevice(null)} onSubmit={handleAssignUser} isSaving={isSaving} />}
      {editingDevice && <EditDeviceModal device={editingDevice} onClose={() => setEditingDevice(null)} onSubmit={handleEditDevice} isSaving={isSaving} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Device, HistoryEntry } from '../types';
import DeviceCard from './DeviceCard';
import TimelineItem from './TimelineItem';

interface DashboardViewProps {
  devices: Device[];
  history: HistoryEntry[];
  onViewAll: () => void;
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  isAdmin: boolean;
  onSearch: (val: string) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ devices, history, onViewAll, onAction, onEdit, isAdmin, onSearch }) => {
  const [localSearch, setLocalSearch] = useState('');

  const stats = {
    total: devices.length,
    available: devices.filter(d => d.status === 'AVAILABLE').length,
    assigned: devices.filter(d => d.status === 'ASSIGNED').length,
    pending: devices.filter(d => d.status === 'PENDING').length,
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (localSearch.trim()) {
      onSearch(localSearch);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Quick Search Section */}
      <section className="bg-primary/5 p-5 rounded-[32px] border border-primary/10">
        <h2 className="text-sm font-bold text-primary mb-3 px-1">Tìm kiếm nhanh thiết bị</h2>
        <form onSubmit={handleSearchSubmit} className="relative">
          <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-primary/40">search</span>
          <input 
            type="text" 
            placeholder="Tên, mã tài sản, người dùng, vị trí..."
            className="w-full bg-white border-transparent rounded-2xl py-3.5 pl-12 pr-4 text-sm focus:ring-2 focus:ring-primary/20 shadow-sm font-medium"
            value={localSearch}
            onChange={e => setLocalSearch(e.target.value)}
          />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 bg-primary text-white p-2 rounded-xl flex items-center justify-center hover:scale-105 active:scale-95 transition-all"
          >
            <span className="material-symbols-outlined text-[20px]">arrow_forward</span>
          </button>
        </form>
      </section>

      {/* Stats Section */}
      <section>
        <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-3 px-1">
          {isAdmin ? 'Tổng quan hệ thống' : 'Tài sản của tôi'}
        </h2>
        <div className="grid grid-cols-2 gap-3">
          <StatCard icon="devices" label="Tổng số" value={stats.total} iconColor="text-primary" />
          <StatCard icon="check_circle" label="Sẵn sàng" value={stats.available} iconColor="text-status-available" />
          <StatCard icon="person_check" label="Đang cấp" value={stats.assigned} iconColor="text-status-assigned" />
          <StatCard icon="pending" label="Đang chờ" value={stats.pending} iconColor="text-status-pending" />
        </div>
      </section>

      {/* Featured Inventory */}
      <section>
        <div className="flex items-center justify-between mb-3 px-1">
          <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
            {isAdmin ? 'Thiết bị gần đây' : 'Thiết bị của tôi'}
          </h2>
          <button onClick={onViewAll} className="text-primary text-xs font-bold hover:underline">Xem tất cả</button>
        </div>
        <div className="grid grid-cols-1 gap-4">
          {devices.length > 0 ? (
            devices.slice(0, 3).map(device => (
              <DeviceCard key={device.id} device={device} onAction={onAction} onEdit={onEdit} isAdmin={isAdmin} />
            ))
          ) : (
            <div className="bg-white p-8 rounded-3xl border border-dashed border-slate-200 text-center">
              <span className="material-symbols-outlined text-slate-300 text-4xl mb-2">no_devices</span>
              <p className="text-sm text-slate-400 font-medium">Chưa có thiết bị nào.</p>
            </div>
          )}
        </div>
      </section>

      {/* Timeline Section */}
      <section>
        <div className="flex items-center justify-between mb-4 px-1">
          <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
            {isAdmin ? 'Lịch sử hoạt động' : 'Lịch sử tài sản của tôi'}
          </h2>
          <button className="text-primary text-xs font-bold hover:underline">Chi tiết</button>
        </div>
        <div className="relative ml-2">
          {history.length > 0 && <div className="absolute left-[7px] top-2 bottom-2 w-[2px] bg-slate-200"></div>}
          <div className="space-y-6">
            {history.length > 0 ? (
              history.slice(0, 10).map(entry => (
                <TimelineItem key={entry.id} entry={entry} />
              ))
            ) : (
              <p className="text-xs text-slate-400 italic ml-6">Chưa có hoạt động nào gần đây.</p>
            )}
          </div>
        </div>
      </section>
    </div>
  );
};

const StatCard: React.FC<{ icon: string; label: string; value: number; iconColor: string }> = ({ icon, label, value, iconColor }) => (
  <div className="bg-white p-4 rounded-xl shadow-subtle border border-slate-100">
    <div className="flex items-center gap-2 mb-1">
      <span className={`material-symbols-outlined ${iconColor} text-[20px]`}>{icon}</span>
      <span className="text-xs font-semibold text-slate-500">{label}</span>
    </div>
    <div className="text-xl font-bold text-slate-800">{value}</div>
  </div>
);

export default DashboardView;

import React, { useState } from 'react';
import { Device } from '../types';
import DeviceCard from './DeviceCard';

interface DevicesViewProps {
  devices: Device[];
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  isAdmin: boolean;
  searchTerm: string;
  setSearchTerm: (val: string) => void;
}

const DevicesView: React.FC<DevicesViewProps> = ({ devices, onAction, onEdit, isAdmin, searchTerm, setSearchTerm }) => {
  const [filter, setFilter] = useState<string>('All');

  const filteredDevices = devices.filter(d => {
    const searchLower = searchTerm.toLowerCase();
    const matchesSearch = 
      d.name.toLowerCase().includes(searchLower) || 
      d.tagId.toLowerCase().includes(searchLower) ||
      (d.assignedTo && d.assignedTo.toLowerCase().includes(searchLower)) ||
      d.location.toLowerCase().includes(searchLower);

    const matchesFilter = filter === 'All' || d.type === filter;
    return matchesSearch && matchesFilter;
  });

  const categories = ['All', 'Laptop', 'Ideahub', 'Mini PC', 'Mobile Phone', 'Tablet', 'Workstation', 'Peripheral'];

  return (
    <div className="space-y-6 animate-fadeIn">
      <div>
        <h2 className="text-2xl font-bold text-slate-800 mb-1">
          {isAdmin ? 'Danh mục thiết bị' : 'Thiết bị của tôi'}
        </h2>
        <p className="text-sm text-slate-500">
          {isAdmin ? 'Theo dõi và quản lý tất cả tài sản phần cứng.' : 'Các tài sản được cấp phát cho bạn.'}
        </p>
      </div>

      <div className="space-y-4">
        {/* Search Bar */}
        <div className="relative group">
          <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors">search</span>
          <input 
            type="text" 
            placeholder={isAdmin ? "Tìm theo tên, ID, người dùng hoặc vị trí..." : "Tìm kiếm trong thiết bị của bạn..."}
            className="w-full bg-white border-slate-200 rounded-2xl py-3.5 pl-12 pr-12 text-sm focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all shadow-sm font-medium"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-500"
            >
              <span className="material-symbols-outlined text-[20px]">cancel</span>
            </button>
          )}
        </div>

        {/* Filter Chips */}
        <div className="flex gap-2 overflow-x-auto pb-2 -mx-1 px-1 no-scrollbar">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all ${
                filter === cat ? 'bg-primary text-white shadow-md' : 'bg-white text-slate-500 border border-slate-200 hover:bg-slate-50'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredDevices.map(device => (
          <DeviceCard key={device.id} device={device} onAction={onAction} onEdit={onEdit} isAdmin={isAdmin} />
        ))}
        {filteredDevices.length === 0 && (
          <div className="col-span-full flex flex-col items-center justify-center py-12 text-slate-400">
            <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-3">
              <span className="material-symbols-outlined text-4xl opacity-20">search_off</span>
            </div>
            <p className="font-medium">{isAdmin ? 'Không tìm thấy thiết bị phù hợp.' : 'Bạn không có tài sản nào trong mục này.'}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default DevicesView;

import React, { useState, useEffect } from 'react';
import { Device, HistoryEntry } from '../types';
import DeviceCard from './DeviceCard';
import TimelineItem from './TimelineItem';

interface DashboardViewProps {
  devices: Device[];
  history: HistoryEntry[];
  onViewAll: () => void;
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  isAdmin: boolean;
  onSearch: (val: string) => void;
}

const AnalogClock: React.FC = () => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const seconds = time.getSeconds();
  const minutes = time.getMinutes();
  const hours = time.getHours();

  const sDegree = (seconds / 60) * 360;
  const mDegree = (minutes / 60) * 360 + (seconds / 60) * 6;
  const hDegree = (hours / 12) * 360 + (minutes / 60) * 30;

  return (
    <div className="relative w-24 h-24 rounded-full border-[3px] border-white shadow-inner flex items-center justify-center bg-white/20 backdrop-blur-sm">
      {/* Clock Face Dots */}
      {[...Array(12)].map((_, i) => (
        <div 
          key={i} 
          className="absolute w-0.5 h-1 bg-white/40" 
          style={{ transform: `rotate(${i * 30}deg) translateY(-38px)` }}
        />
      ))}

      {/* Hands */}
      <div 
        className="absolute w-1 h-8 bg-slate-800 rounded-full origin-bottom" 
        style={{ transform: `rotate(${hDegree}deg) translateY(-16px)` }}
      />
      <div 
        className="absolute w-0.5 h-10 bg-slate-600 rounded-full origin-bottom" 
        style={{ transform: `rotate(${mDegree}deg) translateY(-20px)` }}
      />
      <div 
        className="absolute w-[1px] h-11 bg-primary origin-bottom" 
        style={{ transform: `rotate(${sDegree}deg) translateY(-22px)` }}
      />

      {/* Center Point */}
      <div className="absolute w-2 h-2 bg-primary rounded-full border-2 border-white shadow-sm z-10" />
    </div>
  );
};

const MiniCalendar: React.FC = () => {
  const now = new Date();
  const days = ['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'];
  const monthNames = ['Tháng 1', 'Tháng 2', 'Tháng 3', 'Tháng 4', 'Tháng 5', 'Tháng 6', 'Tháng 7', 'Tháng 8', 'Tháng 9', 'Tháng 10', 'Tháng 11', 'Tháng 12'];

  return (
    <div className="bg-white/90 backdrop-blur-md rounded-2xl p-3 shadow-sm border border-white/50 flex flex-col items-center justify-center min-w-[100px]">
      <span className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">{monthNames[now.getMonth()]}</span>
      <span className="text-3xl font-black text-slate-800 leading-none">{now.getDate()}</span>
      <span className="text-[10px] font-bold text-slate-400 mt-1">{days[now.getDay()]}, {now.getFullYear()}</span>
    </div>
  );
};

const DashboardView: React.FC<DashboardViewProps> = ({ devices, history, onViewAll, onAction, onEdit, isAdmin, onSearch }) => {
  const [localSearch, setLocalSearch] = useState('');
  const [greeting, setGreeting] = useState('');

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Chào buổi sáng');
    else if (hour < 18) setGreeting('Chào buổi chiều');
    else setGreeting('Chào buổi tối');
  }, []);

  const stats = {
    total: devices.length,
    available: devices.filter(d => d.status === 'AVAILABLE').length,
    assigned: devices.filter(d => d.status === 'ASSIGNED').length,
    pending: devices.filter(d => d.status === 'PENDING').length,
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (localSearch.trim()) {
      onSearch(localSearch);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* Command Center Hero Section */}
      <section className="relative overflow-hidden bg-gradient-to-br from-primary to-blue-700 rounded-[40px] p-6 text-white shadow-2xl shadow-primary/20">
        <div className="absolute -top-24 -right-24 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-12 -left-12 w-48 h-48 bg-blue-400/20 rounded-full blur-2xl"></div>

        <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
          <div className="flex-1">
            <h1 className="text-2xl font-black tracking-tight mb-1">{greeting}!</h1>
            <p className="text-blue-100 text-sm font-medium opacity-90">Hôm nay hệ thống của bạn hoạt động ổn định.</p>
          </div>
          <div className="flex items-center gap-4">
            <MiniCalendar />
            <AnalogClock />
          </div>
        </div>

        <form onSubmit={handleSearchSubmit} className="relative z-10 group">
          <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-primary">search</span>
          <input 
            type="text" 
            placeholder="Tìm nhanh: Tên, mã tài sản, người dùng..."
            className="w-full bg-white/95 border-none rounded-2xl py-4 pl-12 pr-4 text-sm text-slate-800 focus:ring-4 focus:ring-white/20 shadow-xl font-medium transition-all group-focus-within:bg-white"
            value={localSearch}
            onChange={e => setLocalSearch(e.target.value)}
          />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 bg-primary text-white p-2.5 rounded-xl flex items-center justify-center hover:scale-105 active:scale-95 transition-all shadow-lg"
          >
            <span className="material-symbols-outlined text-[20px]">arrow_forward</span>
          </button>
        </form>
      </section>

      {/* Stats Section with improved design */}
      <section>
        <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-4 px-1 flex items-center gap-2">
          <span className="w-1.5 h-1.5 rounded-full bg-primary"></span>
          {isAdmin ? 'Chỉ số hệ thống' : 'Tài sản cá nhân'}
        </h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard icon="inventory_2" label="Tổng tài sản" value={stats.total} color="bg-blue-50 text-blue-600" />
          <StatCard icon="verified" label="Sẵn sàng" value={stats.available} color="bg-green-50 text-green-600" />
          <StatCard icon="assignment_ind" label="Đang cấp" value={stats.assigned} color="bg-red-50 text-red-600" />
          <StatCard icon="hourglass_empty" label="Đang chờ" value={stats.pending} color="bg-orange-50 text-orange-600" />
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Featured Inventory */}
        <section>
          <div className="flex items-center justify-between mb-4 px-1">
            <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
               {isAdmin ? 'Thiết bị mới cập nhật' : 'Thiết bị của tôi'}
            </h2>
            <button onClick={onViewAll} className="text-primary text-xs font-bold hover:underline">Tất cả</button>
          </div>
          <div className="space-y-4">
            {devices.length > 0 ? (
              devices.slice(0, 3).map(device => (
                <DeviceCard key={device.id} device={device} onAction={onAction} onEdit={onEdit} isAdmin={isAdmin} />
              ))
            ) : (
              <div className="bg-white p-12 rounded-[32px] border border-dashed border-slate-200 text-center">
                <span className="material-symbols-outlined text-slate-200 text-5xl mb-3">inventory</span>
                <p className="text-sm text-slate-400 font-medium italic">Danh sách trống</p>
              </div>
            )}
          </div>
        </section>

        {/* Timeline Section */}
        <section>
          <div className="flex items-center justify-between mb-4 px-1">
            <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-slate-300"></span>
               {isAdmin ? 'Nhật ký hoạt động' : 'Lịch sử tài sản'}
