      ))}

      {/* Hands Container - Using wrappers to ensure perfect center rotation */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        {/* Hour Hand */}
        <div 
          className="absolute w-1 h-7 bg-slate-800 rounded-full" 
          style={{ 
            transform: `rotate(${hDegree}deg) translateY(-50%)`,
            transformOrigin: '50% 100%',
            bottom: '50%'
