        {/* Minute Hand */}
        <div 
          className="absolute w-0.5 h-10 bg-slate-600 rounded-full" 
          style={{ 
            transform: `rotate(${mDegree}deg) translateY(-50%)`,
            transformOrigin: '50% 100%',
            bottom: '50%'
          }}
        />
        {/* Second Hand */}
        <div 
          className="absolute w-[1px] h-11 bg-primary" 
          style={{ 
            transform: `rotate(${sDegree}deg) translateY(-50%)`,
            transformOrigin: '50% 100%',
            bottom: '50%'
          }}
        />
      </div>

      {/* Center Point */}
      <div className="absolute w-2.5 h-2.5 bg-primary rounded-full border-2 border-white shadow-sm z-10" />
    </div>
  );
};

