Để khắc phục lỗi thiếu ID khi thêm người dùng (và thiết bị) trên Google Sheet, tôi đã cập nhật mã **Google Apps Script** để tự động tạo ID duy nhất nếu cột "ID" tồn tại. Đồng thời, tôi cập nhật `App.tsx` để tối ưu hóa việc xử lý dữ liệu.

### 1. Mã Google Apps Script mới (Cập nhật và dán lại toàn bộ)

Mã này xử lý việc tự động tạo mã định danh (ID) như `USER-XXXX` hoặc `DEV-XXXX` khi bạn thêm mới từ ứng dụng, giúp dữ liệu trên Sheet luôn đầy đủ và nhất quán.

```javascript
/**
 * GOOGLE APPS SCRIPT - ASSETFLOW BACKEND v2.5
 * Tự động tạo ID cho thiết bị và người dùng nếu cột ID trống.
 */

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = {
    devices: ss.getSheetByName("devices") || ss.getSheets()[0],
    users: ss.getSheetByName("users") || ss.getSheets()[1],
    history: ss.getSheetByName("history") || ss.getSheets()[2]
  };

  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error parsing JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  const action = data.action;
  const timestamp = data.timestamp || new Date().toISOString();
  const performer = data.performedBy || "Hệ thống";

  try {
    switch (action) {
      case 'ADD_DEVICE':
        const devHeaders = getHeaders(sheets.devices);
        const generatedDevId = "DEV-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        const newDevRow = devHeaders.map(h => {
          const key = h.toLowerCase().replace(/\s+/g, '');
          if (key === 'id') return generatedDevId;
          if (key.includes('tagid') || key.includes('mãtài')) return data.tagId;
          if (key.includes('name') || key.includes('tên')) return data.name;
          if (key.includes('type') || key.includes('loại')) return data.type;
          if (key.includes('location') || key.includes('vịtrí')) return data.location;
          if (key.includes('config') || key.includes('cấu')) return data.configuration;
          if (key.includes('accessory') || key.includes('phụkiện')) return data.accessory;
          if (key.includes('note') || key.includes('ghichú')) return data.note;
          if (key.includes('status') || key.includes('trạng')) return 'AVAILABLE';
          if (key.includes('updated') || key.includes('cậpnhật')) return timestamp;
          return "";
        });
        sheets.devices.appendRow(newDevRow);
        logHistory(sheets.history, data.tagId, data.name, "ADD", performer, "Kho");
        break;

      case 'ADD_USER':
        const userHeaders = getHeaders(sheets.users);
        const generatedUserId = "USER-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        const newUserRow = userHeaders.map(h => {
          const key = h.toLowerCase().replace(/\s+/g, '');
          if (key === 'id') return generatedUserId; // ĐÃ THÊM: Xử lý cột ID
          if (key.includes('name') || key.includes('tên')) return data.name;
          if (key.includes('employeeid') || key.includes('mãnhân')) return data.employeeId;
          if (key.includes('role')) return data.role;
          if (key.includes('avatar')) return data.avatarUrl || "";
          return "";
        });
        sheets.users.appendRow(newUserRow);
        logHistory(sheets.history, "N/A", data.name, "ADD_USER", performer, "Hệ thống");
        break;

      case 'EDIT_DEVICE':
        updateDeviceFields(sheets.devices, data.tagId, data, timestamp);
        logHistory(sheets.history, data.tagId, data.name, "UPDATE", performer, "Thông tin");
        break;

      case 'DELETE_DEVICE':
        deleteRowByValue(sheets.devices, ["tagid", "mã tài sản"], data.tagId);
        logHistory(sheets.history, data.tagId, data.deviceName, "DELETE", performer, "Xóa");
        break;

      case 'DELETE_USER':
        deleteRowByValue(sheets.users, ["employeeid", "mã nhân viên"], data.employeeId);
        break;

      case 'ASSIGN_DEVICE':
        updateDeviceStatus(sheets.devices, data.tagId, "ASSIGNED", data.userName, timestamp);
        logHistory(sheets.history, data.tagId, data.deviceName, "ASSIGN", performer, data.userName);
        break;

      case 'RETURN_DEVICE':
        updateDeviceStatus(sheets.devices, data.tagId, "AVAILABLE", "", timestamp);
        logHistory(sheets.history, data.tagId, data.deviceName, "RETURN", performer, "Kho");
        break;
    }

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

// Các hàm Helper (giống như phiên bản trước nhưng tối ưu hơn)
function getHeaders(sheet) {
  return sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
}

function findColumnIndex(headers, possibleNames) {
  for (let i = 0; i < headers.length; i++) {
    const header = headers[i].toLowerCase().replace(/\s+/g, '');
    if (possibleNames.some(name => header.includes(name.replace(/\s+/g, '')))) return i + 1;
  }
  return -1;
}

function deleteRowByValue(sheet, headerNames, value) {
  const headers = getHeaders(sheet);
  const colIndex = findColumnIndex(headers, headerNames);
  if (colIndex === -1) return false;
  const data = sheet.getRange(2, colIndex, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < data.length; i++) {
    if (data[i][0].toString() === value.toString()) {
      sheet.deleteRow(i + 2);
      return true;
    }
  }
  return false;
}

function updateDeviceStatus(sheet, tagId, status, user, timestamp) {
  const headers = getHeaders(sheet);
  const tagCol = findColumnIndex(headers, ["tagid", "mã tài sản"]);
  const statusCol = findColumnIndex(headers, ["status", "trạng thái"]);
  const userCol = findColumnIndex(headers, ["assigned", "người sử dụng"]);
  const updateCol = findColumnIndex(headers, ["last updated", "cập nhật"]);

  const data = sheet.getRange(2, tagCol, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < data.length; i++) {
    if (data[i][0].toString() === tagId.toString()) {
      const row = i + 2;
      if (statusCol !== -1) sheet.getRange(row, statusCol).setValue(status);
      if (userCol !== -1) sheet.getRange(row, userCol).setValue(user);
      if (updateCol !== -1) sheet.getRange(row, updateCol).setValue(timestamp);
      return true;
    }
  }
}

function updateDeviceFields(sheet, tagId, newData, timestamp) {
  const headers = getHeaders(sheet);
  const tagCol = findColumnIndex(headers, ["tagid", "mã tài sản"]);
  const data = sheet.getRange(2, tagCol, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < data.length; i++) {
    if (data[i][0].toString() === tagId.toString()) {
      const row = i + 2;
      headers.forEach((h, idx) => {
        const col = idx + 1;
        const key = h.toLowerCase().replace(/\s+/g, '');
        if (key.includes('name') || key.includes('tên')) sheet.getRange(row, col).setValue(newData.name);
        if (key.includes('type') || key.includes('loại')) sheet.getRange(row, col).setValue(newData.type);
        if (key.includes('location') || key.includes('vịtrí')) sheet.getRange(row, col).setValue(newData.location);
        if (key.includes('config') || key.includes('cấu')) sheet.getRange(row, col).setValue(newData.configuration);
        if (key.includes('accessory') || key.includes('phụkiện')) sheet.getRange(row, col).setValue(newData.accessory);
        if (key.includes('note') || key.includes('ghichú')) sheet.getRange(row, col).setValue(newData.note);
        if (key.includes('status') || key.includes('trạng')) sheet.getRange(row, col).setValue(newData.status);
        if (key.includes('updated') || key.includes('cậpnhật')) sheet.getRange(row, col).setValue(timestamp);
      });
      return true;
    }
  }
}

function logHistory(sheet, tagId, deviceName, action, performer, target) {
  sheet.appendRow([
    "HIST-" + Math.random().toString(36).substr(2, 6).toUpperCase(),
    tagId,
    deviceName,
    action,
    new Date().toISOString(),
    performer,
    target
  ]);
}
```

