              <div className="w-5 h-5 border-2 border-primary/20 border-t-primary rounded-full animate-spin"></div>
              <span className="text-xs font-bold text-slate-600">Đang đồng bộ Sheet...</span>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

payload.text:
Lỗi bạn gặp phải là do trong code Script cũ, khi thực hiện lệnh `ADD_USER`, mình đã truyền tên người dùng vào cột "Tên thiết bị" (Cột 3) và chữ "Hệ thống" vào cột "Đối tượng" (Cột cuối), dẫn đến nhật ký trông rất kỳ cục như trong ảnh bạn gửi.

Dưới đây là bản cập nhật **Google Apps Script v2.6** đã sửa lỗi này. Nhật ký (History) bây giờ sẽ được ghi chép logic hơn: 
- **Tên thiết bị**: Sẽ ghi là "Tài khoản: [Tên người dùng]" hoặc "Nhân sự".
- **Đối tượng (Target)**: Sẽ ghi tên người được tác động.
- **Tự động tìm cột**: Code mới sẽ tự tìm tiêu đề cột để điền dữ liệu, không quan trọng bạn sắp xếp cột theo thứ tự nào.

### 1. Cập nhật Google Apps Script (Thay thế toàn bộ code cũ)

```javascript
/**
 * GOOGLE APPS SCRIPT - ASSETFLOW BACKEND v2.6
 * Sửa lỗi ghi nhật ký (History) và đồng bộ hóa ID.
 */

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = {
    devices: ss.getSheetByName("devices") || ss.getSheets()[0],
    users: ss.getSheetByName("users") || ss.getSheets()[1],
    history: ss.getSheetByName("history") || ss.getSheets()[2]
  };

  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error parsing JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  const action = data.action;
  const timestamp = data.timestamp || new Date().toISOString();
  const performer = data.performedBy || "Hệ thống";

  try {
    switch (action) {
      case 'ADD_DEVICE':
        const devId = "DEV-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        appendDataByHeader(sheets.devices, {
          id: devId,
          tagid: data.tagId,
          name: data.name,
          type: data.type,
          location: data.location,
          configuration: data.configuration,
          accessory: data.accessory,
          note: data.note,
          status: 'AVAILABLE',
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.name,
          action: "ADD",
          performer: performer,
          target: "Kho"
        });
        break;

      case 'ADD_USER':
        const userId = "USER-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        appendDataByHeader(sheets.users, {
          id: userId,
          name: data.name,
          employeeid: data.employeeId,
          role: data.role,
          avatarurl: data.avatarUrl || ""
        });
        // SỬA LỖI TẠI ĐÂY: Ghi nhật ký thêm người dùng rõ ràng hơn
        logHistory(sheets.history, {
          tagid: "N/A",
          devicename: "Nhân sự mới",
          action: "ADD_USER",
          performer: performer,
          target: data.name // Tên người dùng mới nằm ở cột Target
        });
        break;

      case 'EDIT_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          name: data.name,
          type: data.type,
          location: data.location,
          configuration: data.configuration,
          accessory: data.accessory,
          note: data.note,
          status: data.status,
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.name,
          action: "UPDATE",
          performer: performer,
          target: "Thông tin"
        });
        break;

      case 'DELETE_DEVICE':
        deleteRowByValue(sheets.devices, "tagid", data.tagId);
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "DELETE",
          performer: performer,
          target: "Xóa bỏ"
        });
        break;

      case 'DELETE_USER':
        deleteRowByValue(sheets.users, "employeeid", data.employeeId);
        logHistory(sheets.history, {
          tagid: "N/A",
          devicename: "Xóa nhân sự",
          action: "DELETE_USER",
          performer: performer,
          target: data.name
        });
        break;

      case 'ASSIGN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          status: "ASSIGNED",
          assignedto: data.userName,
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "ASSIGN",
          performer: performer,
          target: data.userName
        });
        break;

      case 'RETURN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          status: "AVAILABLE",
          assignedto: "",
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "RETURN",
          performer: performer,
          target: "Kho"
        });
        break;
    }

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

// --- HÀM TIỆN ÍCH THÔNG MINH (DÙNG HEADER ĐỂ ĐIỀN DỮ LIỆU) ---

function getHeaders(sheet) {
  return sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => h.toString().toLowerCase().replace(/\s+/g, ''));
}

function appendDataByHeader(sheet, dataObj) {
  const headers = getHeaders(sheet);
  const newRow = headers.map(h => dataObj[h] || "");
  sheet.appendRow(newRow);
}

function updateRowByHeader(sheet, idHeaderName, idValue, dataObj) {
  const headers = getHeaders(sheet);
  const idColIndex = headers.indexOf(idHeaderName) + 1;
  if (idColIndex === 0) return;

  const colData = sheet.getRange(2, idColIndex, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < colData.length; i++) {
    if (colData[i][0].toString() === idValue.toString()) {
      const row = i + 2;
      for (let key in dataObj) {
        const col = headers.indexOf(key) + 1;
        if (col > 0) sheet.getRange(row, col).setValue(dataObj[key]);
      }
      return true;
    }
  }
}

function deleteRowByValue(sheet, headerName, value) {
  const headers = getHeaders(sheet);
  const colIndex = headers.indexOf(headerName) + 1;
  if (colIndex === 0) return;
  const colData = sheet.getRange(2, colIndex, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < colData.length; i++) {
    if (colData[i][0].toString() === value.toString()) {
      sheet.deleteRow(i + 2);
      return true;
    }
  }
}

function logHistory(sheet, hData) {
  const headers = getHeaders(sheet);
  const historyObj = {
    id: "HIST-" + Math.random().toString(36).substr(2, 6).toUpperCase(),
    tagid: hData.tagid || "N/A",
    mataisan: hData.tagid || "N/A",
    devicename: hData.devicename || "",
    ten: hData.devicename || "",
    action: hData.action || "",
    timestamp: new Date().toISOString(),
    thoigian: new Date().toISOString(),
    performer: hData.performer || "",
    nguoithuchien: hData.performer || "",
    target: hData.target || "",
    doituong: hData.target || ""
  };

  const newRow = headers.map(h => historyObj[h] || "");
  sheet.appendRow(newRow);
}
```

### 2. Hướng dẫn sửa lỗi triệt để:

1.  **Vào Apps Script**: Xóa toàn bộ code cũ và dán code v2.6 ở trên vào.
2.  **Deployment**: Nhấn **Deploy** -> **New Deployment**. Chọn **Web App**, Access: **Anyone**, sau đó nhấn Deploy. (Bạn không cần thay đổi URL trong `App.tsx` nếu URL Web App cũ vẫn hoạt động, nhưng tốt nhất nên dùng URL mới nhất từ bản Deploy này).
3.  **Tên cột trên Sheet**: Để code hoạt động hoàn hảo, hãy đảm bảo các tiêu đề (Headers) ở dòng 1 trong Sheet của bạn có chứa các từ khóa sau (không phân biệt hoa thường, không quan trọng dấu cách):
    *   Sheet `devices`: `id`, `tagid`, `name`, `type`, `location`, `status`, `lastupdated`.
    *   Sheet `users`: `id`, `name`, `employeeid`, `role`.
    *   Sheet `history`: `id`, `tagid`, `devicename`, `action`, `timestamp`, `performer`, `target`.

Bản cập nhật này sẽ giúp cột nhật ký của bạn sạch sẽ và đúng cột 100%!

