Để khắc phục triệt để lỗi ghi nhật ký (History) bị lệch cột và lỗi thiếu ID khi thêm người dùng, tôi đã cập nhật mã nguồn cả ở phía **Google Apps Script (v2.7)** và **Frontend (App.tsx)**.

Lý do lỗi bạn gặp phải (như trong ảnh) là do phiên bản Script cũ đang dùng cách truyền dữ liệu theo vị trí cố định, trong khi cấu trúc cột của bạn có thể đã thay đổi. Phiên bản v2.7 này sẽ tự động tìm tiêu đề cột để điền, đảm bảo chính xác 100%.

### 1. Cập nhật Google Apps Script (v2.7 - QUAN TRỌNG)
Vui lòng xóa toàn bộ mã cũ trong Apps Script và dán đoạn mã này vào. Sau đó nhấn **Deploy -> New Deployment**.

```javascript
/**
 * GOOGLE APPS SCRIPT - ASSETFLOW BACKEND v2.7
 * Tối ưu hóa cho cấu trúc cột:
 * History: id, tagid, devicename, action, timestamp, performer, target
 * Devices: id, tagId, name, type, location, configuration, Accessory, Note, status, assignedTo, lastUpdated
 * Users: ID, Name, Employee ID, Role, Created At, Timestamp
 */

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = {
    devices: ss.getSheetByName("devices") || ss.getSheets()[0],
    users: ss.getSheetByName("users") || ss.getSheets()[1],
    history: ss.getSheetByName("history") || ss.getSheets()[2]
  };

  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  const action = data.action;
  const timestamp = data.timestamp || new Date().toISOString();
  const performer = data.performedBy || "Hệ thống";

  try {
    switch (action) {
      case 'ADD_DEVICE':
        const devId = "DEV-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        appendDataByHeader(sheets.devices, {
          id: devId,
          tagid: data.tagId,
          name: data.name,
          type: data.type,
          location: data.location,
          configuration: data.configuration,
          accessory: data.accessory,
          note: data.note,
          status: 'AVAILABLE',
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.name,
          action: "ADD",
          performer: performer,
          target: "Kho"
        });
        break;

      case 'ADD_USER':
        const userId = "USER-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        // Ghi vào bảng Users theo đúng tiêu đề cột của bạn
        appendDataByHeader(sheets.users, {
          id: userId,
          name: data.name,
          employeeid: data.employeeId,
          role: data.role,
          createdat: timestamp,
          timestamp: timestamp
        });
        // Ghi vào nhật ký đúng cột
        logHistory(sheets.history, {
          tagid: "N/A",
          devicename: "Nhân sự mới",
          action: "ADD_USER",
          performer: performer,
          target: data.name // Tên người dùng mới
        });
        break;

      case 'EDIT_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          name: data.name,
          type: data.type,
          location: data.location,
          configuration: data.configuration,
          accessory: data.accessory,
          note: data.note,
          status: data.status,
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.name,
          action: "UPDATE",
          performer: performer,
          target: "Cập nhật"
        });
        break;

      case 'DELETE_DEVICE':
        deleteRowByValue(sheets.devices, "tagid", data.tagId);
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "DELETE",
          performer: performer,
          target: "Hệ thống"
        });
        break;

      case 'DELETE_USER':
        deleteRowByValue(sheets.users, "employeeid", data.employeeId);
        logHistory(sheets.history, {
          tagid: "N/A",
          devicename: "Xóa nhân sự",
          action: "DELETE_USER",
          performer: performer,
          target: data.name
        });
        break;

      case 'ASSIGN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          status: "ASSIGNED",
          assignedto: data.userName,
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "ASSIGN",
          performer: performer,
          target: data.userName
        });
        break;

      case 'RETURN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, {
          status: "AVAILABLE",
          assignedto: "",
          lastupdated: timestamp
        });
        logHistory(sheets.history, {
          tagid: data.tagId,
          devicename: data.deviceName,
          action: "RETURN",
          performer: performer,
          target: "Kho"
        });
        break;
    }
    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

