function getCleanHeaders(sheet) {
  return sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => 
    h.toString().toLowerCase().replace(/\s+/g, '')
  );
}

function appendDataByHeader(sheet, dataObj) {
  const headers = getCleanHeaders(sheet);
  const newRow = headers.map(h => {
    // Tìm giá trị trong dataObj khớp với tiêu đề cột (đã làm sạch)
    return dataObj[h] !== undefined ? dataObj[h] : "";
  });
  sheet.appendRow(newRow);
}

function updateRowByHeader(sheet, idHeaderName, idValue, dataObj) {
  const headers = getCleanHeaders(sheet);
  const idColIndex = headers.indexOf(idHeaderName.toLowerCase().replace(/\s+/g, '')) + 1;
  if (idColIndex === 0) return;

  const colData = sheet.getRange(2, idColIndex, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < colData.length; i++) {
    if (colData[i][0].toString() === idValue.toString()) {
      const row = i + 2;
      for (let key in dataObj) {
        const col = headers.indexOf(key.toLowerCase().replace(/\s+/g, '')) + 1;
        if (col > 0) sheet.getRange(row, col).setValue(dataObj[key]);
      }
      return true;
    }
  }
}

function deleteRowByValue(sheet, headerName, value) {
  const headers = getCleanHeaders(sheet);
  const colIndex = headers.indexOf(headerName.toLowerCase().replace(/\s+/g, '')) + 1;
  if (colIndex === 0) return;
  const colData = sheet.getRange(2, colIndex, sheet.getLastRow() - 1, 1).getValues();
  for (let i = 0; i < colData.length; i++) {
    if (colData[i][0].toString() === value.toString()) {
      sheet.deleteRow(i + 2);
      return true;
    }
  }
}

function logHistory(sheet, hData) {
  const headers = getCleanHeaders(sheet);
  const historyObj = {
    id: "HIST-" + Math.random().toString(36).substr(2, 6).toUpperCase(),
    tagid: hData.tagid || hData.tagId || "N/A",
    devicename: hData.devicename || hData.deviceName || "",
    action: hData.action || "",
    timestamp: new Date().toISOString(),
    performer: hData.performer || "",
    target: hData.target || ""
  };

  const newRow = headers.map(h => historyObj[h] !== undefined ? historyObj[h] : "");
  sheet.appendRow(newRow);
}
