Để tối ưu hóa việc load dữ liệu mà không cần "Publish to Web" dưới dạng CSV (vốn có độ trễ và kém bảo mật), chúng ta sẽ chuyển sang sử dụng chính **Google Apps Script làm API JSON**. 

Cách tiếp cận này có 3 ưu điểm lớn:
1. **Tốc độ**: Lấy toàn bộ dữ liệu (Devices, Users, History) chỉ trong **1 lần gọi API duy nhất**.
2. **Bảo mật**: Bạn không cần chia sẻ công khai file CSV. Chỉ những ai có URL của Web App mới lấy được dữ liệu.
3. **Chính xác**: Tránh được lỗi parsing CSV thủ công ở frontend.

Dưới đây là đặc tả thay đổi:
- **Backend (Apps Script)**: Thêm hàm `doGet` để trả về JSON cho 3 bảng.
- **Frontend (App.tsx)**: Gỡ bỏ các URL CSV, cập nhật hàm `fetchData` để gọi trực tiếp vào Script.

### Bước 1: Cập nhật Google Apps Script (v3.0)
Vui lòng thay thế toàn bộ mã trong Google Apps Script của bạn bằng mã dưới đây:

```javascript
/**
 * GOOGLE APPS SCRIPT - ASSETFLOW BACKEND v3.0 (JSON API)
 * Không cần Publish CSV. Tự động trả về toàn bộ dữ liệu qua GET.
 */

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const action = e.parameter.action;

  if (action === 'GET_DATA') {
    const data = {
      devices: getSheetDataAsJson(ss.getSheetByName("devices") || ss.getSheets()[0]),
      users: getSheetDataAsJson(ss.getSheetByName("users") || ss.getSheets()[1]),
      history: getSheetDataAsJson(ss.getSheetByName("history") || ss.getSheets()[2])
    };

    return ContentService.createTextOutput(JSON.stringify(data))
      .setMimeType(ContentService.MimeType.JSON);
  }
  return ContentService.createTextOutput("Invalid Action").setMimeType(ContentService.MimeType.TEXT);
}

function getSheetDataAsJson(sheet) {
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return [];

  const headers = data[0].map(h => h.toString().toLowerCase().replace(/\s+/g, ''));
  return data.slice(1).map(row => {
    const obj = {};
    headers.forEach((h, i) => {
      obj[h] = row[i];
    });
    return obj;
  });
}

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = {
    devices: ss.getSheetByName("devices") || ss.getSheets()[0],
    users: ss.getSheetByName("users") || ss.getSheets()[1],
    history: ss.getSheetByName("history") || ss.getSheets()[2]
  };

  let data = JSON.parse(e.postData.contents);
  const action = data.action;
  const timestamp = data.timestamp || new Date().toISOString();
  const performer = data.performedBy || "Hệ thống";

  try {
    switch (action) {
      case 'ADD_DEVICE':
        const devId = "DEV-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        appendDataByHeader(sheets.devices, {
          id: devId, tagid: data.tagId, name: data.name, type: data.type, 
          location: data.location, configuration: data.configuration, 
          accessory: data.accessory, note: data.note, status: 'AVAILABLE', lastupdated: timestamp
        });
        logHistory(sheets.history, { tagid: data.tagId, devicename: data.name, action: "ADD", performer: performer, target: "Kho" });
        break;

      case 'ADD_USER':
        const userId = "USER-" + Math.random().toString(36).substr(2, 6).toUpperCase();
        appendDataByHeader(sheets.users, { id: userId, name: data.name, employeeid: data.employeeId, role: data.role, createdat: timestamp, timestamp: timestamp });
        logHistory(sheets.history, { tagid: "N/A", devicename: "Nhân sự mới", action: "ADD_USER", performer: performer, target: data.name });
        break;

      case 'EDIT_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, { name: data.name, type: data.type, location: data.location, configuration: data.configuration, accessory: data.accessory, note: data.note, status: data.status, lastupdated: timestamp });
        logHistory(sheets.history, { tagid: data.tagId, devicename: data.name, action: "UPDATE", performer: performer, target: "Hệ thống" });
        break;

      case 'DELETE_DEVICE':
        deleteRowByValue(sheets.devices, "tagid", data.tagId);
        break;

      case 'DELETE_USER':
        deleteRowByValue(sheets.users, "employeeid", data.employeeId);
        break;

      case 'ASSIGN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, { status: "ASSIGNED", assignedto: data.userName, lastupdated: timestamp });
        logHistory(sheets.history, { tagid: data.tagId, devicename: data.deviceName, action: "ASSIGN", performer: performer, target: data.userName });
        break;

      case 'RETURN_DEVICE':
        updateRowByHeader(sheets.devices, "tagid", data.tagId, { status: "AVAILABLE", assignedto: "", lastupdated: timestamp });
        logHistory(sheets.history, { tagid: data.tagId, devicename: data.deviceName, action: "RETURN", performer: performer, target: "Kho" });
        break;
    }
    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

// Giữ lại các hàm helper (appendDataByHeader, updateRowByHeader, deleteRowByValue, logHistory) từ bản v2.7
function getCleanHeaders(sheet) { return sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0].map(h => h.toString().toLowerCase().replace(/\s+/g, '')); }
function appendDataByHeader(sheet, dataObj) { const headers = getCleanHeaders(sheet); const newRow = headers.map(h => dataObj[h] !== undefined ? dataObj[h] : ""); sheet.appendRow(newRow); }
function updateRowByHeader(sheet, idHeaderName, idValue, dataObj) { const headers = getCleanHeaders(sheet); const idColIndex = headers.indexOf(idHeaderName.toLowerCase().replace(/\s+/g, '')) + 1; if (idColIndex === 0) return; const colData = sheet.getRange(2, idColIndex, sheet.getLastRow() - 1, 1).getValues(); for (let i = 0; i < colData.length; i++) { if (colData[i][0].toString() === idValue.toString()) { const row = i + 2; for (let key in dataObj) { const col = headers.indexOf(key.toLowerCase().replace(/\s+/g, '')) + 1; if (col > 0) sheet.getRange(row, col).setValue(dataObj[key]); } return true; } } }
function deleteRowByValue(sheet, headerName, value) { const headers = getCleanHeaders(sheet); const colIndex = headers.indexOf(headerName.toLowerCase().replace(/\s+/g, '')) + 1; if (colIndex === 0) return; const colData = sheet.getRange(2, colIndex, sheet.getLastRow() - 1, 1).getValues(); for (let i = 0; i < colData.length; i++) { if (colData[i][0].toString() === value.toString()) { sheet.deleteRow(i + 2); return true; } } }
function logHistory(sheet, hData) { const headers = getCleanHeaders(sheet); const historyObj = { id: "HIST-" + Math.random().toString(36).substr(2, 6).toUpperCase(), tagid: hData.tagid || "N/A", devicename: hData.devicename || "", action: hData.action || "", timestamp: new Date().toISOString(), performer: hData.performer || "", target: hData.target || "" }; const newRow = headers.map(h => historyObj[h] !== undefined ? historyObj[h] : ""); sheet.appendRow(newRow); }
```

