              {currentUser.role} {isAdmin ? '' : '- VIEW ONLY'}
            </span>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100" disabled={isLoading || isSaving}>
            <span className={`material-symbols-outlined ${isLoading || isSaving ? 'animate-spin' : ''}`}>sync</span>
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-12">
        {error && (
          <div className="bg-red-50 border border-red-100 text-red-600 p-6 rounded-[32px] mb-6 shadow-sm animate-fadeIn">
            <div className="flex items-center gap-3 font-black uppercase tracking-widest text-[11px] mb-2">
              <span className="material-symbols-outlined text-red-500 text-[20px]">warning</span>
              {error.message}
            </div>
            <p className="text-xs font-medium opacity-80 mb-4 leading-relaxed">{error.details}</p>
            <div className="flex gap-2">
              <button 
                onClick={fetchData} 
