            <div className="flex-1 min-w-0">
              <p className="text-[10px] uppercase tracking-tighter text-slate-400 font-bold">Phụ kiện</p>
              <p className="text-xs text-slate-700 font-medium">{device.accessory || 'Không có'}</p>
            </div>
