import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { TabType, Device, HistoryEntry, AssetStatus, User } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import UsersView from './components/UsersView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';
import AddUserModal from './components/AddUserModal';
import AssignUserModal from './components/AssignUserModal';
import EditDeviceModal from './components/EditDeviceModal';
import EditUserModal from './components/EditUserModal';
import IdentificationView from './components/IdentificationView';

const GOOGLE_SCRIPT_APP_URL = 'https://script.google.com/macros/s/AKfycbywRpgG-YElFth55EkcjLYQgH4bepTf_yMYsVI9X2ktgf9hABt6sxxa-D7Tj2ySf7Q1/exec'.trim();

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [isAddDeviceOpen, setIsAddDeviceOpen] = useState(false);
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [assigningDevice, setAssigningDevice] = useState<Device | null>(null);
  const [editingDevice, setEditingDevice] = useState<Device | null>(null);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<{ message: string; details?: string; isNetworkError?: boolean } | null>(null);

  const isAdmin = currentUser?.role === 'ADMIN';
  const isOperation = currentUser?.role === 'OPERATION';
  const isManagement = isAdmin || isOperation;

  const existingTagIds = useMemo(() => devices.map(d => d.tagId), [devices]);

  const visibleDevices = useMemo(() => {
    if (!currentUser) return [];
    if (isManagement) return devices;
    return devices.filter(d => 
      d.assignedTo === currentUser.name || 
      d.assignedTo === currentUser.employeeId
    );
  }, [devices, currentUser, isManagement]);

  const visibleHistory = useMemo(() => {
    if (!currentUser) return [];
    if (isManagement) return history;
    const deviceIds = new Set(visibleDevices.map(d => d.tagId));
    return history.filter(h => 
      deviceIds.has(h.deviceId) || 
      h.target === currentUser.name || 
      h.target === currentUser.employeeId
    );
  }, [history, visibleDevices, currentUser, isManagement]);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const url = `${GOOGLE_SCRIPT_APP_URL}?action=GET_DATA&cb=${Date.now()}`;
      const response = await fetch(url, {
        method: 'GET',
        headers: { 'Accept': 'application/json' },
        redirect: 'follow',
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const data = await response.json();

      setDevices((data.devices || []).map((d: any, index: number) => ({
        id: d.id || d.tagid || `dev-${index}`,
        tagId: d.tagid || 'N/A',
        name: d.name || 'Không tên',
        type: d.type || 'Khác',
        location: d.location || 'Chưa rõ',
        configuration: d.configuration || '',
        accessory: d.accessory || '',
        note: d.note || '',
        status: (d.status?.toString().toUpperCase() as AssetStatus) || 'AVAILABLE',
        assignedTo: d.assignedto || undefined,
        lastUpdated: d.lastupdated || new Date().toISOString()
      })));

      setUsers((data.users || []).map((u: any, index: number) => ({
        id: u.id || u.employeeid || `user-${index}`,
        name: u.name || 'Unknown User',
        employeeId: u.employeeid || 'N/A',
        role: (u.role?.toString().toUpperCase() as any) || 'STAFF',
        avatarUrl: u.avatarurl || undefined
      })));

      setHistory((data.history || []).map((h: any, index: number) => {
        let normalizedAction: HistoryEntry['action'] = 'UPDATE';
        const rawAction = (h.action || '').toString().toUpperCase();
        if (rawAction.includes('ASSIGN')) normalizedAction = 'ASSIGN';
        else if (rawAction.includes('RETURN')) normalizedAction = 'RETURN';
        else if (rawAction.includes('REPAIR')) normalizedAction = 'REPAIR';
        return {
          id: h.id || `hist-${index}`,
          deviceId: h.tagid || 'N/A',
          deviceName: h.devicename || 'N/A',
          action: normalizedAction,
          timestamp: h.timestamp ? new Date(h.timestamp).toLocaleString('vi-VN') : 'Không rõ',
          performer: h.performer || 'Hệ thống',
          target: h.target || ''
        };
      }).reverse());
    } catch (err: any) {
      setError({ message: "Lỗi kết nối", details: err.message, isNetworkError: true });
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleIdentify = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => setCurrentUser(null);

  const sendPostRequest = async (payload: any) => {
    setIsSaving(true);
    try {
      await fetch(GOOGLE_SCRIPT_APP_URL, { 
        method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, 
        body: JSON.stringify(payload) 
      });
      setTimeout(() => {
        fetchData();
        setIsSaving(false);
        setIsAddDeviceOpen(false);
        setIsAddUserOpen(false);
        setEditingDevice(null);
        setEditingUser(null);
        setAssigningDevice(null);
      }, 2000);
    } catch (err: any) {
      setError({ message: "Lỗi cập nhật", details: err.message });
      setIsSaving(false);
    }
  };

  const handleAddDevice = (newDevice: any) => {
    if (!isAdmin) return;
    sendPostRequest({ ...newDevice, action: 'ADD_DEVICE', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleEditDevice = (updatedDevice: Device) => {
    if (!isAdmin) return;
    sendPostRequest({ ...updatedDevice, action: 'EDIT_DEVICE', tagId: updatedDevice.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleDeleteDevice = (id: string) => {
    if (!isAdmin) return;
    const device = devices.find(d => d.id === id);
    if (device && window.confirm(`Xóa thiết bị ${device.name}?`)) {
      sendPostRequest({ action: 'DELETE_DEVICE', tagId: device.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
    }
  };

  const handleAddUser = (newUser: any) => {
    if (!isManagement) return;
    sendPostRequest({ ...newUser, action: 'ADD_USER', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleEditUser = (updatedUser: User) => {
    if (!isAdmin) return;
    sendPostRequest({ ...updatedUser, action: 'EDIT_USER', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleDeleteUser = (id: string) => {
    if (!isAdmin) return;
    const user = users.find(u => u.id === id);
    if (user && window.confirm(`Xóa nhân sự ${user.name}?`)) {
      sendPostRequest({ action: 'DELETE_USER', employeeId: user.employeeId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
    }
  };

  const handleAction = (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    if (!isManagement) return;
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;
    if (action === 'ASSIGN') setAssigningDevice(device);
    else if (window.confirm(`Thu hồi ${device.name}?`)) {
      sendPostRequest({ action: 'RETURN_DEVICE', tagId: device.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
    }
  };

  const handleFabClick = () => {
    if (activeTab === 'users' && isManagement) setIsAddUserOpen(true);
    else if (activeTab === 'devices' && isAdmin) setIsAddDeviceOpen(true);
  };

  const showFab = (activeTab === 'users' && isManagement) || (activeTab === 'devices' && isAdmin);

  if (!currentUser) return <IdentificationView users={users} onSelect={handleIdentify} isLoading={isLoading} />;

  return (
    <div className="flex flex-col min-h-screen pb-20 bg-background">
      <header className="sticky top-0 z-30 flex items-center justify-between px-4 h-16 bg-white border-b border-slate-200">
        <div className="flex items-center gap-2">
          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center shadow-lg shadow-primary/20">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-slate-800 tracking-tight leading-none">AssetFlow</span>
            <span className={`text-[9px] font-bold uppercase mt-0.5 tracking-wider ${isAdmin ? 'text-primary' : isOperation ? 'text-orange-500' : 'text-slate-400'}`}>
              {currentUser.role} {isManagement ? 'MODE' : '- VIEW ONLY'}
            </span>
          </div>
        </div>
        <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100" disabled={isLoading}>
          <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-12">
        {activeTab === 'dashboard' && <DashboardView devices={visibleDevices} history={visibleHistory} onViewAll={() => setActiveTab('devices')} onAction={handleAction} onEdit={setEditingDevice} onDelete={handleDeleteDevice} isAdmin={isAdmin} isManagement={isManagement} onSearch={(v) => { setSearchTerm(v); setActiveTab('devices'); }} />}
        {activeTab === 'devices' && <DevicesView devices={visibleDevices} onAction={handleAction} onEdit={setEditingDevice} onDelete={handleDeleteDevice} isAdmin={isAdmin} isManagement={isManagement} searchTerm={searchTerm} setSearchTerm={setSearchTerm} />}
        {activeTab === 'users' && <UsersView users={users} isAdmin={isAdmin} isManagement={isManagement} onDelete={handleDeleteUser} onEditUser={setEditingUser} />}
        {activeTab === 'settings' && (
          <div className="flex flex-col items-center justify-center pt-10 space-y-6">
            <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-xl w-full text-center">
               <div className="w-24 h-24 bg-primary/5 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-white shadow-inner">
                  {currentUser.avatarUrl ? <img src={currentUser.avatarUrl} className="w-full h-full object-cover rounded-full" /> : <span className="material-symbols-outlined text-primary text-5xl">person</span>}
               </div>
               <h3 className="text-xl font-bold text-slate-800 mb-1">{currentUser.name}</h3>
               <p className="text-sm text-slate-400 font-medium mb-6">ID: {currentUser.employeeId} | Vai trò: {currentUser.role}</p>
               <button onClick={handleLogout} className="w-full py-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold hover:bg-red-50 hover:text-red-500 hover:border-red-100 transition-all">Đăng xuất</button>
            </div>
          </div>
        )}
      </main>

      {showFab && (
        <div className="fixed bottom-24 right-6 z-40">
          <button onClick={handleFabClick} className="w-14 h-14 rounded-full shadow-fab bg-primary text-white flex items-center justify-center hover:scale-110 active:scale-95 transition-all">
            <span className="material-symbols-outlined text-[32px]">add</span>
          </button>
        </div>
      )}

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} />
      {isAddDeviceOpen && <AddDeviceModal existingTagIds={existingTagIds} onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {isAddUserOpen && <AddUserModal onClose={() => setIsAddUserOpen(false)} onSubmit={handleAddUser} isSaving={isSaving} />}
      {assigningDevice && <AssignUserModal users={users} onClose={() => setAssigningDevice(null)} onSubmit={(u) => sendPostRequest({ action: 'ASSIGN_DEVICE', tagId: assigningDevice.tagId, userName: u.name, timestamp: new Date().toISOString(), performedBy: currentUser?.name })} isSaving={isSaving} />}
      {editingDevice && <EditDeviceModal device={editingDevice} onClose={() => setEditingDevice(null)} onSubmit={handleEditDevice} isSaving={isSaving} />}
      {editingUser && <EditUserModal user={editingUser} onClose={() => setEditingUser(null)} onSubmit={handleEditUser} isSaving={isSaving} />}
    </div>
  );
};

export default App;

/**
 * AssetFlow Backend Script
 * Hướng dẫn: Dán mã này vào Google Apps Script liên kết với Spreadsheet của bạn.
 * Spreadsheet cần có 3 sheet: "Devices", "Users", "History"
 */

function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'GET_DATA') {
    return ContentService.createTextOutput(JSON.stringify({
      devices: getSheetData(ss.getSheetByName("Devices")),
      users: getSheetData(ss.getSheetByName("Users")),
      history: getSheetData(ss.getSheetByName("History"))
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var data = JSON.parse(e.postData.contents);
  var action = data.action;

  var devicesSheet = ss.getSheetByName("Devices");
  var usersSheet = ss.getSheetByName("Users");
  var historySheet = ss.getSheetByName("History");

  var timestamp = data.timestamp || new Date().toISOString();
  var performer = data.performedBy || "Hệ thống";

  if (action === 'ADD_DEVICE') {
    devicesSheet.appendRow([
      data.tagId, data.name, data.type, 'AVAILABLE', '', 
      data.location, data.configuration, data.accessory, data.note, timestamp
    ]);
  } 

  else if (action === 'EDIT_DEVICE') {
    var rows = devicesSheet.getDataRange().getValues();
    for (var i = 1; i < rows.length; i++) {
      if (rows[i][0] == data.tagId) {
        devicesSheet.getRange(i + 1, 2).setValue(data.name);
        devicesSheet.getRange(i + 1, 3).setValue(data.type);
        devicesSheet.getRange(i + 1, 4).setValue(data.status);
        devicesSheet.getRange(i + 1, 6).setValue(data.location);
        devicesSheet.getRange(i + 1, 7).setValue(data.configuration);
        devicesSheet.getRange(i + 1, 8).setValue(data.accessory);
        devicesSheet.getRange(i + 1, 9).setValue(data.note);
        devicesSheet.getRange(i + 1, 10).setValue(timestamp);
        break;
      }
    }
  }

  else if (action === 'DELETE_DEVICE') {
    var rows = devicesSheet.getDataRange().getValues();
    for (var i = 1; i < rows.length; i++) {
      if (rows[i][0] == data.tagId) {
        devicesSheet.deleteRow(i + 1);
        break;
      }
    }
  }

  else if (action === 'ADD_USER') {
    usersSheet.appendRow([data.name, data.employeeId, data.role, '']);
  }

  // --- LOGIC MỚI CHO EDIT_USER ---
  else if (action === 'EDIT_USER') {
    var rows = usersSheet.getDataRange().getValues();
    for (var i = 1; i < rows.length; i++) {
      // Tìm theo Employee ID (Cột 2 - index 1)
      if (rows[i][1] == data.employeeId) {
        usersSheet.getRange(i + 1, 1).setValue(data.name); // Cập nhật Tên (Cột 1)
        usersSheet.getRange(i + 1, 3).setValue(data.role); // Cập nhật Quyền (Cột 3)
        // Nếu có avatarurl trong payload thì cập nhật (Cột 4)
        if (data.avatarUrl !== undefined) {
          usersSheet.getRange(i + 1, 4).setValue(data.avatarUrl);
        }
        break;
      }
    }

    // Log hành động thay đổi quyền vào history nếu cần
    historySheet.appendRow([
      timestamp, 'SYSTEM', performer, 'UPDATE_USER', data.name, 'Updated user profile/role'
    ]);
  }

  else if (action === 'DELETE_USER') {
    var rows = usersSheet.getDataRange().getValues();
    for (var i = 1; i < rows.length; i++) {
      if (rows[i][1] == data.employeeId) {
        usersSheet.deleteRow(i + 1);
        break;
      }
    }
  }

  else if (action === 'ASSIGN_DEVICE') {
    updateDeviceStatus(devicesSheet, data.tagId, 'ASSIGNED', data.userName, timestamp);
    historySheet.appendRow([
      timestamp, data.tagId, performer, 'ASSIGN', data.userName, 'Cấp phát thiết bị'
    ]);
  }

  else if (action === 'RETURN_DEVICE') {
    var rows = devicesSheet.getDataRange().getValues();
    var currentUser = "";
    for (var i = 1; i < rows.length; i++) {
      if (rows[i][0] == data.tagId) {
        currentUser = rows[i][4];
        break;
      }
    }
    updateDeviceStatus(devicesSheet, data.tagId, 'AVAILABLE', '', timestamp);
    historySheet.appendRow([
      timestamp, data.tagId, performer, 'RETURN', currentUser, 'Thu hồi thiết bị'
    ]);
  }

  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}

function updateDeviceStatus(sheet, tagId, status, assignedTo, timestamp) {
  var rows = sheet.getDataRange().getValues();
  for (var i = 1; i < rows.length; i++) {
    if (rows[i][0] == tagId) {
      sheet.getRange(i + 1, 4).setValue(status);
      sheet.getRange(i + 1, 5).setValue(assignedTo);
      sheet.getRange(i + 1, 10).setValue(timestamp);
      break;
    }
  }
}

function getSheetData(sheet) {
  if (!sheet) return [];
  var data = sheet.getDataRange().getValues();
  var headers = data[0];
  var result = [];
  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      var key = headers[j].toString().toLowerCase().replace(/ /g, "");
      obj[key] = data[i][j];
    }
    result.push(obj);
  }
  return result;
}

/**
 * AssetFlow Backend Script - Robust Version
 * Hướng dẫn: 
 * 1. Dán mã này vào Apps Script.
 * 2. Đảm bảo các sheet "Devices", "Users", "History" có dòng đầu tiên là tiêu đề.
 * 3. Sau khi lưu, chọn "Deploy" -> "New Deployment" -> "Web App" -> "Anyone".
 */

function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'GET_DATA') {
    return ContentService.createTextOutput(JSON.stringify({
      devices: getSheetData(ss.getSheetByName("Devices")),
      users: getSheetData(ss.getSheetByName("Users")),
      history: getSheetData(ss.getSheetByName("History"))
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var data;

  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  var action = data.action;
  var timestamp = data.timestamp || new Date().toISOString();
  var performer = data.performedBy || "Hệ thống";

  // --- XỬ LÝ DEVICES ---
  if (action === 'ADD_DEVICE' || action === 'EDIT_DEVICE' || action === 'DELETE_DEVICE' || action === 'ASSIGN_DEVICE' || action === 'RETURN_DEVICE') {
    var sheet = ss.getSheetByName("Devices");
    var historySheet = ss.getSheetByName("History");
    var rows = sheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, ""); });

    var tagIdIdx = headers.indexOf("tagid");

    if (action === 'ADD_DEVICE') {
      sheet.appendRow([
        data.tagId, data.name, data.type, 'AVAILABLE', '', 
        data.location, data.configuration, data.accessory, data.note, timestamp
      ]);
    } else {
      // Tìm dòng chứa thiết bị dựa trên tagId
      var targetRow = -1;
      for (var i = 1; i < rows.length; i++) {
        if (String(rows[i][tagIdIdx]).trim() == String(data.tagId).trim()) {
          targetRow = i + 1;
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_DEVICE') {
          updateRowByHeaders(sheet, targetRow, headers, {
            "name": data.name,
            "type": data.type,
            "status": data.status,
            "location": data.location,
            "configuration": data.configuration,
            "accessory": data.accessory,
            "note": data.note,
            "lastupdated": timestamp
          });
        } else if (action === 'DELETE_DEVICE') {
          sheet.deleteRow(targetRow);
        } else if (action === 'ASSIGN_DEVICE') {
          updateRowByHeaders(sheet, targetRow, headers, { "status": "ASSIGNED", "assignedto": data.userName, "lastupdated": timestamp });
          historySheet.appendRow([timestamp, data.tagId, performer, 'ASSIGN', data.userName, 'Cấp phát']);
        } else if (action === 'RETURN_DEVICE') {
          var currentUser = rows[targetRow-1][headers.indexOf("assignedto")];
          updateRowByHeaders(sheet, targetRow, headers, { "status": "AVAILABLE", "assignedto": "", "lastupdated": timestamp });
          historySheet.appendRow([timestamp, data.tagId, performer, 'RETURN', currentUser, 'Thu hồi']);
        }
      }
    }
  }

  // --- XỬ LÝ USERS ---
  else if (action === 'ADD_USER' || action === 'EDIT_USER' || action === 'DELETE_USER') {
    var sheet = ss.getSheetByName("Users");
    var historySheet = ss.getSheetByName("History");
    var rows = sheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, ""); });

    var empIdIdx = headers.indexOf("employeeid");

    if (action === 'ADD_USER') {
      sheet.appendRow([data.name, data.employeeId, data.role, '']);
    } else {
      var targetRow = -1;
      for (var i = 1; i < rows.length; i++) {
        // So sánh an toàn: chuyển về String và xóa khoảng trắng
        if (String(rows[i][empIdIdx]).trim() == String(data.employeeId).trim()) {
          targetRow = i + 1;
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_USER') {
          updateRowByHeaders(sheet, targetRow, headers, {
            "name": data.name,
            "role": data.role,
            "avatarurl": data.avatarUrl
          });
          historySheet.appendRow([timestamp, 'USER_MGMT', performer, 'UPDATE_USER', data.name, 'Cập nhật hồ sơ/quyền']);
        } else if (action === 'DELETE_USER') {
          sheet.deleteRow(targetRow);
        }
      }
    }
  }

  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}

/**
 * Cập nhật các ô trong một dòng dựa trên tên tiêu đề
 */
function updateRowByHeaders(sheet, rowNum, headers, dataMap) {
  for (var key in dataMap) {
    var colIdx = headers.indexOf(key.toLowerCase());
    if (colIdx !== -1 && dataMap[key] !== undefined) {
      sheet.getRange(rowNum, colIdx + 1).setValue(dataMap[key]);
    }
  }
}

function getSheetData(sheet) {
  if (!sheet) return [];
  var data = sheet.getDataRange().getValues();
  if (data.length < 1) return [];

  var headers = data[0];
  var result = [];
  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      var key = headers[j].toString().toLowerCase().replace(/ /g, "");
      obj[key] = data[i][j];
    }
    result.push(obj);
  }
  return result;
}

import React, { useState } from 'react';
import { Device, AssetStatus } from '../types';

interface DeviceCardProps {
  device: Device;
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  onDelete: (id: string) => void;
  isAdmin: boolean;
  isManagement: boolean;
}

const DeviceCard: React.FC<DeviceCardProps> = ({ device, onAction, onEdit, onDelete, isAdmin, isManagement }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isAssigned = device.status === 'ASSIGNED';
  const isAvailable = device.status === 'AVAILABLE';

  const getStatusStyles = (status: AssetStatus) => {
    switch (status) {
      case 'AVAILABLE': return 'bg-green-50 text-status-available';
      case 'ASSIGNED': return 'bg-red-50 text-status-assigned';
      case 'PENDING': return 'bg-orange-50 text-status-pending';
      case 'REPAIR': return 'bg-amber-50 text-amber-600';
      default: return 'bg-slate-50 text-slate-500';
    }
  };

  const getStatusLabel = (status: AssetStatus) => {
    switch (status) {
      case 'AVAILABLE': return 'Sẵn sàng';
      case 'ASSIGNED': return 'Đang sử dụng';
      case 'PENDING': return 'Chờ duyệt';
      case 'REPAIR': return 'Sửa chữa';
      default: return status;
    }
  };

  return (
    <div onClick={() => setIsExpanded(!isExpanded)} className={`bg-white rounded-2xl border border-slate-100 shadow-subtle overflow-hidden flex flex-col transition-all cursor-pointer ${isExpanded ? 'ring-2 ring-primary/20' : ''}`}>
      <div className="p-4">
        <div className="flex justify-between items-start mb-3">
          <div className="flex-1 min-w-0 pr-2">
            <h3 className="font-bold text-slate-800 text-base truncate">{device.name}</h3>
            <p className="text-xs text-slate-400">ID: {device.tagId} • <span className="text-primary font-bold uppercase">{device.type}</span></p>
          </div>
          <span className={`text-[10px] px-2.5 py-1 rounded-full font-bold uppercase ${getStatusStyles(device.status)}`}>{getStatusLabel(device.status)}</span>
        </div>

        {isAssigned && device.assignedTo && (
          <div className="mb-3 px-3 py-2 bg-red-50/50 rounded-xl border border-red-100 flex items-center gap-2">
            <span className="material-symbols-outlined text-[16px] text-red-500">person</span>
            <span className="text-xs font-bold text-red-700 truncate">Sử dụng: {device.assignedTo}</span>
          </div>
        )}

        <div className="space-y-2">
          <div className="flex items-center gap-2 text-xs text-slate-600">
             <span className="material-symbols-outlined text-[16px] text-slate-400">settings_input_component</span>
             <span className="truncate">{device.configuration || 'N/A'}</span>
          </div>
          <div className="flex items-center gap-2 text-xs text-slate-600">
             <span className="material-symbols-outlined text-[16px] text-slate-400">location_on</span>
             <span>{device.location}</span>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-4 pt-4 border-t border-slate-50 space-y-2 animate-fadeIn">
            <p className="text-xs text-slate-500"><b>Phụ kiện:</b> {device.accessory || 'Không'}</p>
            <p className="text-xs text-slate-500"><b>Ghi chú:</b> {device.note || 'Trống'}</p>
            <p className="text-[10px] text-slate-400 uppercase font-bold">Cập nhật: {device.lastUpdated}</p>
          </div>
        )}
      </div>

      {isManagement ? (
        <div onClick={(e) => e.stopPropagation()} className="border-t border-slate-50 p-3 bg-slate-50/30 flex gap-2">
          {/* Nút EDIT chỉ hiện cho ADMIN */}
          {isAdmin && (
            <button onClick={() => onEdit(device)} className="flex-1 bg-white border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-600 flex items-center justify-center gap-1.5 hover:bg-slate-50">
              <span className="material-symbols-outlined text-[16px]">edit</span> Sửa
            </button>
          )}

          {/* Nút Hành động: Cấp phát / Thu hồi / Khóa */}
          {isAssigned ? (
            <button onClick={() => onAction(device.id, 'RETURN')} className="flex-1 bg-white border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-600 flex items-center justify-center gap-1.5 hover:bg-slate-50">
              <span className="material-symbols-outlined text-[16px]">keyboard_return</span> Thu hồi
            </button>
          ) : isAvailable ? (
            <button onClick={() => onAction(device.id, 'ASSIGN')} className="flex-1 bg-primary text-white py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-1.5 hover:bg-blue-600">
              <span className="material-symbols-outlined text-[16px]">person_add</span> Cấp phát
            </button>
          ) : (
            <div className="flex-1 bg-slate-100 border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-400 flex items-center justify-center gap-1.5 cursor-not-allowed">
              <span className="material-symbols-outlined text-[16px]">lock</span> {device.status === 'PENDING' ? 'Đang chờ' : 'Đang sửa'}
            </div>
          )}

          {/* Nút DELETE chỉ hiện cho ADMIN khi là PENDING hoặc AVAILABLE */}
          {isAdmin && (device.status === 'PENDING' || device.status === 'AVAILABLE') && (
            <button onClick={() => onDelete(device.id)} className="w-10 h-10 bg-white border border-red-100 rounded-lg text-red-500 flex items-center justify-center hover:bg-red-500 hover:text-white transition-all">
              <span className="material-symbols-outlined text-[20px]">delete</span>
            </button>
          )}
        </div>
      ) : (
        <div className="border-t border-slate-50 p-2.5 bg-slate-50/10 flex justify-center italic text-[10px] text-slate-400 uppercase font-bold">
           View Only
        </div>
      )}
    </div>
  );
};

