/**
 * AssetFlow Backend Script - Fixed Column Version
 * Hướng dẫn: 
 * 1. Dán mã này vào Apps Script.
 * 2. Đảm bảo các sheet "Devices", "Users", "History" có dòng đầu tiên là tiêu đề.
 * 3. Sau khi lưu, chọn "Deploy" -> "New Deployment" -> "Web App" -> "Anyone".
 */

function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'GET_DATA') {
    return ContentService.createTextOutput(JSON.stringify({
      devices: getSheetData(ss.getSheetByName("Devices")),
      users: getSheetData(ss.getSheetByName("Users")),
      history: getSheetData(ss.getSheetByName("History"))
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var data;

  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  var action = data.action;
  var timestamp = data.timestamp || new Date().toISOString();
  var performer = data.performedBy || "Hệ thống";

  // --- XỬ LÝ DEVICES ---
  if (action === 'ADD_DEVICE' || action === 'EDIT_DEVICE' || action === 'DELETE_DEVICE' || action === 'ASSIGN_DEVICE' || action === 'RETURN_DEVICE') {
    var sheet = ss.getSheetByName("Devices");
    var historySheet = ss.getSheetByName("History");
    var rows = sheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, ""); });

    var tagIdIdx = headers.indexOf("tagid");

    if (action === 'ADD_DEVICE') {
      // Khớp chính xác với 11 cột: id, tagId, name, type, location, configuration, Accessory, Note, status, assignedTo, lastUpdated
      sheet.appendRow([
        data.tagId,         // id (dùng tagId làm id)
        data.tagId,         // tagId
        data.name,          // name
        data.type,          // type
        data.location,      // location
        data.configuration, // configuration
        data.accessory,     // Accessory
        data.note,          // Note
        'AVAILABLE',        // status
        '',                 // assignedTo
        timestamp           // lastUpdated
      ]);
    } else {
      // Tìm dòng chứa thiết bị dựa trên tagId
      var targetRow = -1;
      for (var i = 1; i < rows.length; i++) {
        if (String(rows[i][tagIdIdx]).trim() == String(data.tagId).trim()) {
          targetRow = i + 1;
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_DEVICE') {
          updateRowByHeaders(sheet, targetRow, headers, {
            "name": data.name,
            "type": data.type,
            "status": data.status,
            "location": data.location,
            "configuration": data.configuration,
            "accessory": data.accessory,
            "note": data.note,
            "lastupdated": timestamp
          });
        } else if (action === 'DELETE_DEVICE') {
          sheet.deleteRow(targetRow);
        } else if (action === 'ASSIGN_DEVICE') {
          updateRowByHeaders(sheet, targetRow, headers, { "status": "ASSIGNED", "assignedto": data.userName, "lastupdated": timestamp });
          historySheet.appendRow([timestamp, data.tagId, performer, 'ASSIGN', data.userName, 'Cấp phát']);
        } else if (action === 'RETURN_DEVICE') {
          var currentUser = rows[targetRow-1][headers.indexOf("assignedto")];
          updateRowByHeaders(sheet, targetRow, headers, { "status": "AVAILABLE", "assignedto": "", "lastupdated": timestamp });
          historySheet.appendRow([timestamp, data.tagId, performer, 'RETURN', currentUser, 'Thu hồi']);
        }
      }
    }
  }

  // --- XỬ LÝ USERS ---
  else if (action === 'ADD_USER' || action === 'EDIT_USER' || action === 'DELETE_USER') {
    var sheet = ss.getSheetByName("Users");
    var historySheet = ss.getSheetByName("History");
    var rows = sheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, ""); });

    var empIdIdx = headers.indexOf("employeeid");

    if (action === 'ADD_USER') {
      sheet.appendRow([data.name, data.employeeId, data.role, '']);
    } else {
      var targetRow = -1;
      for (var i = 1; i < rows.length; i++) {
        if (String(rows[i][empIdIdx]).trim() == String(data.employeeId).trim()) {
          targetRow = i + 1;
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_USER') {
          updateRowByHeaders(sheet, targetRow, headers, {
            "name": data.name,
            "role": data.role,
            "avatarurl": data.avatarUrl
          });
          historySheet.appendRow([timestamp, 'USER_MGMT', performer, 'UPDATE_USER', data.name, 'Cập nhật hồ sơ/quyền']);
        } else if (action === 'DELETE_USER') {
          sheet.deleteRow(targetRow);
        }
      }
    }
  }

  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}

/**
 * Cập nhật các ô trong một dòng dựa trên tên tiêu đề
 */
function updateRowByHeaders(sheet, rowNum, headers, dataMap) {
  for (var key in dataMap) {
    var colIdx = headers.indexOf(key.toLowerCase());
    if (colIdx !== -1 && dataMap[key] !== undefined) {
      sheet.getRange(rowNum, colIdx + 1).setValue(dataMap[key]);
    }
  }
}

function getSheetData(sheet) {
  if (!sheet) return [];
  var data = sheet.getDataRange().getValues();
  if (data.length < 1) return [];

  var headers = data[0];
  var result = [];
  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      var key = headers[j].toString().toLowerCase().replace(/ /g, "");
      obj[key] = data[i][j];
    }
    result.push(obj);
  }
  return result;
}

