/**
 * Hàm lấy Sheet an toàn, hỗ trợ không phân biệt hoa thường và tự tạo nếu thiếu
 */
function getSafeSheet(ss, name, defaultHeaders) {
  var sheets = ss.getSheets();
  var targetName = name.toLowerCase();
  for (var i = 0; i < sheets.length; i++) {
    if (sheets[i].getName().toLowerCase() === targetName) {
      return sheets[i];
    }
  }
  // Nếu không thấy và có headers mặc định, tự tạo mới
  if (defaultHeaders) {
    var newSheet = ss.insertSheet(name);
    newSheet.appendRow(defaultHeaders);
    return newSheet;
  }
  return null;
}

function updateRowByHeaders(sheet, rowNum, headers, dataMap) {
  for (var key in dataMap) {
    var cleanKey = key.toLowerCase().replace(/ /g, "").replace(/_/g, "");
    var colIdx = headers.indexOf(cleanKey);
    if (colIdx !== -1 && dataMap[key] !== undefined) {
      sheet.getRange(rowNum, colIdx + 1).setValue(dataMap[key]);
    }
  }
}

function getSheetData(sheet) {
  if (!sheet) return [];
  var data = sheet.getDataRange().getValues();
  if (data.length < 1) return [];

  var headers = data[0];
  var result = [];
  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      var key = headers[j].toString().toLowerCase().replace(/ /g, "").replace(/_/g, "");
      obj[key] = data[i][j];
    }
    result.push(obj);
  }
  return result;
}

