      }).reverse());
    } catch (err: any) {
      setError({ message: "Lỗi kết nối", details: err.message, isNetworkError: true });
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleIdentify = (user: User) => {
