/**
 * AssetFlow Backend Script - Universal History Logging & Setup Management
 */

function doGet(e) {
  var action = e.parameter.action;
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'GET_DATA') {
    return ContentService.createTextOutput(JSON.stringify({
      devices: getSheetData(getSafeSheet(ss, "Devices")),
      users: getSheetData(getSafeSheet(ss, "Users")),
      history: getSheetData(getSafeSheet(ss, "History")),
      setup: getSheetData(getSafeSheet(ss, "Setup"))
    })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var data;

  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  var action = data.action;
  var timestamp = data.timestamp || new Date().toISOString();
  var performer = data.performedBy || "Hệ thống";

  var historySheet = getSafeSheet(ss, "History", ["ID", "tagId", "DeviceName", "Action", "Timestamp", "Performer", "Target"]);
  var devicesSheet = getSafeSheet(ss, "Devices");
  var usersSheet = getSafeSheet(ss, "Users");
  var setupSheet = getSafeSheet(ss, "Setup", ["ID", "tagId", "Win", "Unikey", "Printer", "SNMP", "Welink", "WelinkMeeting", "CodeFormat", "QR_Format", "lastUpdated"]);

  if (action === 'SAVE_SETUP') {
    var rows = setupSheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, "").replace(/_/g, ""); });
    var tagIdIdx = headers.indexOf("tagid");

    var targetRow = -1;
    for (var i = 1; i < rows.length; i++) {
      if (tagIdIdx !== -1 && String(rows[i][tagIdIdx]).trim() == String(data.tagId).trim()) {
        targetRow = i + 1;
        break;
      }
    }

    var setupRowData = {
      "id": "setup_" + data.tagId,
      "tagid": data.tagId,
      "win": data.win,
      "unikey": data.unikey,
      "printer": data.printer,
      "snmp": data.snmp,
      "welink": data.welink,
      "welinkmeeting": data.welinkMeeting,
      "codeformat": data.codeFormat,
      "qrformat": data.qrFormat,
      "lastupdated": timestamp
    };

    if (targetRow !== -1) {
      updateRowByHeaders(setupSheet, targetRow, headers, setupRowData);
    } else {
      var rowToAppend = headers.map(function(h) { return setupRowData[h] || ""; });
      setupSheet.appendRow(rowToAppend);
    }

    logHistory(historySheet, data.tagId, "Thiết lập", 'SETUP_CONFIG', timestamp, performer, 'Hệ thống');
    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  }

  // --- XỬ LÝ DEVICES ---
  if (action === 'ADD_DEVICE' || action === 'EDIT_DEVICE' || action === 'DELETE_DEVICE' || action === 'ASSIGN_DEVICE' || action === 'RETURN_DEVICE') {
    if (!devicesSheet) return ContentService.createTextOutput("Error: Devices sheet not found").setMimeType(ContentService.MimeType.TEXT);

    var rows = devicesSheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, "").replace(/_/g, ""); });

    var tagIdIdx = headers.indexOf("tagid");
    var nameIdx = headers.indexOf("name");
    var assignedToIdx = headers.indexOf("assignedto");

    if (action === 'ADD_DEVICE') {
      devicesSheet.appendRow([
        "dev-" + data.tagId, 
        data.tagId,
        data.name,
        data.type,
        data.location,
        data.configuration,
        data.accessory,
        data.note,
        'AVAILABLE',
        '',
        timestamp
      ]);
      logHistory(historySheet, data.tagId, data.name, 'CREATE_DEV', timestamp, performer, 'Kho');
    } else {
      var targetRow = -1;
      var deviceName = "Unknown Device";
      for (var i = 1; i < rows.length; i++) {
        if (tagIdIdx !== -1 && String(rows[i][tagIdIdx]).trim() == String(data.tagId).trim()) {
          targetRow = i + 1;
          deviceName = nameIdx !== -1 ? rows[i][nameIdx] : "Unknown";
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_DEVICE') {
          updateRowByHeaders(devicesSheet, targetRow, headers, {
            "name": data.name,
            "type": data.type,
            "status": data.status,
            "location": data.location,
            "configuration": data.configuration,
            "accessory": data.accessory,
            "note": data.note,
            "lastupdated": timestamp
          });
          logHistory(historySheet, data.tagId, data.name, 'UPDATE_DEV', timestamp, performer, 'Thông tin');
        } else if (action === 'DELETE_DEVICE') {
          devicesSheet.deleteRow(targetRow);
          logHistory(historySheet, data.tagId, deviceName, 'DELETE_DEV', timestamp, performer, 'Hệ thống');
        } else if (action === 'ASSIGN_DEVICE') {
          updateRowByHeaders(devicesSheet, targetRow, headers, { "status": "ASSIGNED", "assignedto": data.userName, "lastupdated": timestamp });
          logHistory(historySheet, data.tagId, deviceName, 'ASSIGN', timestamp, performer, data.userName);
        } else if (action === 'RETURN_DEVICE') {
          var prevUser = assignedToIdx !== -1 ? rows[targetRow-1][assignedToIdx] : "Người dùng";
          updateRowByHeaders(devicesSheet, targetRow, headers, { "status": "AVAILABLE", "assignedto": "", "lastupdated": timestamp });
          logHistory(historySheet, data.tagId, deviceName, 'RETURN', timestamp, performer, prevUser);
        }
      }
    }
  }

  // --- XỬ LÝ USERS ---
  else if (action === 'ADD_USER' || action === 'EDIT_USER' || action === 'DELETE_USER') {
    if (!usersSheet) return ContentService.createTextOutput("Error: Users sheet not found").setMimeType(ContentService.MimeType.TEXT);

    var rows = usersSheet.getDataRange().getValues();
    var headers = rows[0].map(function(h) { return h.toString().toLowerCase().replace(/ /g, "").replace(/_/g, ""); });
    var empIdIdx = headers.indexOf("employeeid");
    var userNameIdx = headers.indexOf("name");

    if (action === 'ADD_USER') {
      usersSheet.appendRow(["user-" + data.employeeId, data.name, data.employeeId, data.role, timestamp, timestamp]);
      logHistory(historySheet, data.employeeId, "NHÂN SỰ", 'USER_ADD', timestamp, performer, data.name);
    } else {
      var targetRow = -1;
      var existingUserName = data.name || "Unknown";
      for (var i = 1; i < rows.length; i++) {
        if (empIdIdx !== -1 && String(rows[i][empIdIdx]).trim() == String(data.employeeId).trim()) {
          targetRow = i + 1;
          existingUserName = rows[i][userNameIdx] || data.name;
          break;
        }
      }

      if (targetRow !== -1) {
        if (action === 'EDIT_USER') {
          updateRowByHeaders(usersSheet, targetRow, headers, { "name": data.name, "role": data.role, "timestamp": timestamp });
          logHistory(historySheet, data.employeeId, "NHÂN SỰ", 'USER_EDIT', timestamp, performer, data.name);
        } else if (action === 'DELETE_USER') {
          usersSheet.deleteRow(targetRow);
          logHistory(historySheet, data.employeeId, "NHÂN SỰ", 'USER_DELETE', timestamp, performer, existingUserName);
        }
      }
    }
  }

  SpreadsheetApp.flush();
  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}

function logHistory(sheet, tagId, deviceName, action, timestamp, performer, target) {
  if (!sheet) return;
  var id = "hist-" + Date.now() + "-" + Math.floor(Math.random() * 1000);
  sheet.appendRow([id, tagId, deviceName, action, timestamp, performer, target]);
}

function getSafeSheet(ss, name, defaultHeaders) {
  var sheets = ss.getSheets();
  var targetName = name.toLowerCase();
  for (var i = 0; i < sheets.length; i++) {
    if (sheets[i].getName().toLowerCase() === targetName) return sheets[i];
  }
  if (defaultHeaders) {
    var newSheet = ss.insertSheet(name);
    newSheet.appendRow(defaultHeaders);
    return newSheet;
  }
  return null;
}

function updateRowByHeaders(sheet, rowNum, headers, dataMap) {
  for (var key in dataMap) {
    var cleanKey = key.toLowerCase().replace(/ /g, "").replace(/_/g, "");
    var colIdx = headers.indexOf(cleanKey);
    if (colIdx !== -1 && dataMap[key] !== undefined) {
      sheet.getRange(rowNum, colIdx + 1).setValue(dataMap[key]);
    }
  }
}

function getSheetData(sheet) {
  if (!sheet) return [];
  var data = sheet.getDataRange().getValues();
  if (data.length < 1) return [];
  var headers = data[0];
  var result = [];
  for (var i = 1; i < data.length; i++) {
    var obj = {};
    for (var j = 0; j < headers.length; j++) {
      var key = headers[j].toString().toLowerCase().replace(/ /g, "").replace(/_/g, "");
      obj[key] = data[i][j];
    }
    result.push(obj);
  }
  return result;
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { TabType, Device, HistoryEntry, AssetStatus, User, SetupData } from './types';
import DashboardView from './components/DashboardView';
import DevicesView from './components/DevicesView';
import UsersView from './components/UsersView';
import SetupView from './components/SetupView';
import Navigation from './components/Navigation';
import AddDeviceModal from './components/AddDeviceModal';
import AddUserModal from './components/AddUserModal';
import AssignUserModal from './components/AssignUserModal';
import EditDeviceModal from './components/EditDeviceModal';
import EditUserModal from './components/EditUserModal';
import SetupModal from './components/SetupModal';
import IdentificationView from './components/IdentificationView';

const GOOGLE_SCRIPT_APP_URL = 'https://script.google.com/macros/s/AKfycbywRpgG-YElFth55EkcjLYQgH4bepTf_yMYsVI9X2ktgf9hABt6sxxa-D7Tj2ySf7Q1/exec'.trim();

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [devices, setDevices] = useState<Device[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [setups, setSetups] = useState<SetupData[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [isAddDeviceOpen, setIsAddDeviceOpen] = useState(false);
  const [isAddUserOpen, setIsAddUserOpen] = useState(false);
  const [assigningDevice, setAssigningDevice] = useState<Device | null>(null);
  const [editingDevice, setEditingDevice] = useState<Device | null>(null);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [settingUpDevice, setSettingUpDevice] = useState<Device | null>(null);

  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<{ message: string; details?: string; isNetworkError?: boolean } | null>(null);

  const isAdmin = currentUser?.role === 'ADMIN';
  const isOperation = currentUser?.role === 'OPERATION';
  const isManagement = isAdmin || isOperation;

  const existingTagIds = useMemo(() => devices.map(d => d.tagId), [devices]);

  const visibleDevices = useMemo(() => {
    if (!currentUser) return [];
    if (isManagement) return devices;
    return devices.filter(d => 
      d.assignedTo === currentUser.name || 
      d.assignedTo === currentUser.employeeId
    );
  }, [devices, currentUser, isManagement]);

  const visibleHistory = useMemo(() => {
    if (!currentUser) return [];
    if (isManagement) return history;
    const deviceIds = new Set(visibleDevices.map(d => d.tagId));
    return history.filter(h => 
      deviceIds.has(h.deviceId) || 
      h.target === currentUser.name || 
      h.target === currentUser.employeeId
    );
  }, [history, visibleDevices, currentUser, isManagement]);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const url = `${GOOGLE_SCRIPT_APP_URL}?action=GET_DATA&cb=${Date.now()}`;
      const response = await fetch(url, {
        method: 'GET',
        headers: { 'Accept': 'application/json' },
        redirect: 'follow',
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const data = await response.json();

      setDevices((data.devices || []).map((d: any, index: number) => {
        const id = d.id || `dev-${d.tagid || index}`;
        return {
          id: id.startsWith('dev-') ? id : `dev-${id}`,
          tagId: d.tagid || 'N/A',
          name: d.name || 'Không tên',
          type: d.type || 'Khác',
          location: d.location || 'Chưa rõ',
          configuration: d.configuration || '',
          accessory: d.accessory || '',
          note: d.note || '',
          status: (d.status?.toString().toUpperCase() as AssetStatus) || 'AVAILABLE',
          assignedTo: d.assignedto || undefined,
          lastUpdated: d.lastupdated || new Date().toISOString()
        };
      }));

      setUsers((data.users || []).map((u: any, index: number) => {
        const id = u.id || `user-${u.employeeid || index}`;
        return {
          id: id.startsWith('user-') ? id : `user-${id}`,
          name: u.name || 'Unknown User',
          employeeId: u.employeeid || 'N/A',
          role: (u.role?.toString().toUpperCase() as any) || 'STAFF',
          avatarUrl: u.avatarurl || undefined
        };
      }));

      setHistory((data.history || []).map((h: any, index: number) => {
        const id = h.id || `hist-${index}`;
        return {
          id: id.startsWith('hist-') ? id : `hist-${id}`,
          deviceId: h.tagid || 'N/A',
          deviceName: h.devicename || 'Không rõ',
          action: h.action || 'UPDATE',
          timestamp: h.timestamp ? new Date(h.timestamp).toLocaleString('vi-VN') : 'Không rõ',
          performer: h.performer || 'Hệ thống',
          target: h.target || ''
        };
      }).reverse());

      setSetups((data.setup || []).map((s: any) => ({
        id: s.id,
        tagId: s.tagid,
        win: !!s.win,
        unikey: !!s.unikey,
        printer: !!s.printer,
        snmp: !!s.snmp,
        welink: !!s.welink,
        welinkMeeting: !!s.welinkmeeting,
        codeFormat: s.codeformat,
        qrFormat: s.qrformat,
        lastUpdated: s.lastupdated
      })));

    } catch (err: any) {
      setError({ message: "Lỗi kết nối", details: err.message, isNetworkError: true });
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const handleIdentify = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => setCurrentUser(null);

  const sendPostRequest = async (payload: any) => {
    setIsSaving(true);
    try {
      await fetch(GOOGLE_SCRIPT_APP_URL, { 
        method: 'POST', mode: 'no-cors', headers: { 'Content-Type': 'text/plain' }, 
        body: JSON.stringify(payload) 
      });
      setTimeout(() => {
        fetchData();
        setIsSaving(false);
        setIsAddDeviceOpen(false);
        setIsAddUserOpen(false);
        setEditingDevice(null);
        setEditingUser(null);
        setAssigningDevice(null);
        setSettingUpDevice(null);
      }, 2000);
    } catch (err: any) {
      setError({ message: "Lỗi cập nhật", details: err.message });
      setIsSaving(false);
    }
  };

  const handleAddDevice = (newDevice: any) => {
    if (!isAdmin) return;
    sendPostRequest({ ...newDevice, action: 'ADD_DEVICE', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleEditDevice = (updatedDevice: Device) => {
    if (!isAdmin) return;
    sendPostRequest({ ...updatedDevice, action: 'EDIT_DEVICE', tagId: updatedDevice.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleDeleteDevice = (id: string) => {
    if (!isAdmin) return;
    const device = devices.find(d => d.id === id);
    if (device && window.confirm(`Xóa thiết bị ${device.name}?`)) {
      sendPostRequest({ action: 'DELETE_DEVICE', tagId: device.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
    }
  };

  const handleAction = (deviceId: string, action: 'ASSIGN' | 'RETURN') => {
    if (!isManagement) return;
    const device = devices.find(d => d.id === deviceId);
    if (!device) return;

    if (action === 'ASSIGN') {
      if (device.status !== 'AVAILABLE') {
        alert("Thiết bị này không sẵn sàng để cấp phát.");
        return;
      }
      setAssigningDevice(device);
    } else if (action === 'RETURN') {
      if (device.status !== 'ASSIGNED') return;
      if (window.confirm(`Thu hồi ${device.name}?`)) {
        sendPostRequest({ action: 'RETURN_DEVICE', tagId: device.tagId, timestamp: new Date().toISOString(), performedBy: currentUser?.name });
      }
    }
  };

  const handleSaveSetup = (setupData: any) => {
    if (!isManagement) return;
    sendPostRequest({ ...setupData, action: 'SAVE_SETUP', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleEditUser = (updatedUser: User) => {
    if (!isAdmin) return;
    sendPostRequest({ ...updatedUser, action: 'EDIT_USER', timestamp: new Date().toISOString(), performedBy: currentUser?.name });
  };

  const handleDeleteUser = (id: string) => {
    if (!isAdmin) return;
    const user = users.find(u => u.id === id);
    if (user && window.confirm(`Xóa nhân sự ${user.name}?`)) {
      sendPostRequest({ 
        action: 'DELETE_USER', 
        employeeId: user.employeeId, 
        name: user.name, 
        timestamp: new Date().toISOString(), 
        performedBy: currentUser?.name 
      });
    }
  };

  const handleFabClick = () => {
    if (activeTab === 'users' && isManagement) setIsAddUserOpen(true);
    else if (activeTab === 'devices' && isAdmin) setIsAddDeviceOpen(true);
  };

  const showFab = (activeTab === 'users' && isManagement) || (activeTab === 'devices' && isAdmin);

  if (!currentUser) return <IdentificationView users={users} onSelect={handleIdentify} isLoading={isLoading} />;

  return (
    <div className="flex flex-col min-h-screen pb-20 bg-background">
      <header className="sticky top-0 z-30 flex items-center justify-between px-4 h-16 bg-white border-b border-slate-200">
        <div className="flex items-center gap-2">
          <div className="bg-primary rounded-lg p-1.5 flex items-center justify-center shadow-lg shadow-primary/20">
            <span className="material-symbols-outlined text-white text-[20px]">inventory_2</span>
          </div>
          <div className="flex flex-col">
            <span className="font-bold text-slate-800 tracking-tight leading-none">AssetFlow</span>
            <span className={`text-[9px] font-bold uppercase mt-0.5 tracking-wider ${isAdmin ? 'text-primary' : isOperation ? 'text-orange-500' : 'text-slate-400'}`}>
              {currentUser.role} {isManagement ? 'MODE' : '- VIEW ONLY'}
            </span>
          </div>
        </div>
        <button onClick={fetchData} className="text-slate-500 p-2 rounded-full hover:bg-slate-100" disabled={isLoading}>
          <span className={`material-symbols-outlined ${isLoading ? 'animate-spin' : ''}`}>sync</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-4 pt-6 pb-12">
        {activeTab === 'dashboard' && <DashboardView devices={visibleDevices} history={visibleHistory} onViewAll={() => setActiveTab('devices')} onAction={handleAction} onEdit={setEditingDevice} onDelete={handleDeleteDevice} onSetup={setSettingUpDevice} isAdmin={isAdmin} isManagement={isManagement} onSearch={(v) => { setSearchTerm(v); setActiveTab('devices'); }} />}
        {activeTab === 'devices' && <DevicesView devices={visibleDevices} onAction={handleAction} onEdit={setEditingDevice} onDelete={handleDeleteDevice} onSetup={setSettingUpDevice} isAdmin={isAdmin} isManagement={isManagement} searchTerm={searchTerm} setSearchTerm={setSearchTerm} />}
        {activeTab === 'users' && <UsersView users={users} isAdmin={isAdmin} isManagement={isManagement} onDelete={handleDeleteUser} onEditUser={setEditingUser} />}
        {activeTab === 'setup' && isAdmin && <SetupView setups={setups} onEdit={(tagId) => {
          const device = devices.find(d => d.tagId === tagId);
          if (device) setSettingUpDevice(device);
        }} />}
        {activeTab === 'settings' && (
          <div className="flex flex-col items-center justify-center pt-10 space-y-6">
            <div className="bg-white p-8 rounded-[40px] border border-slate-100 shadow-xl w-full text-center">
               <div className="w-24 h-24 bg-primary/5 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-white shadow-inner">
                  {currentUser.avatarUrl ? <img src={currentUser.avatarUrl} className="w-full h-full object-cover rounded-full" /> : <span className="material-symbols-outlined text-primary text-5xl">person</span>}
               </div>
               <h3 className="text-xl font-bold text-slate-800 mb-1">{currentUser.name}</h3>
               <p className="text-sm text-slate-400 font-medium mb-6">ID: {currentUser.employeeId} | Vai trò: {currentUser.role}</p>
               <button onClick={handleLogout} className="w-full py-4 rounded-2xl border-2 border-slate-100 text-slate-500 font-bold hover:bg-red-50 hover:text-red-500 hover:border-red-100 transition-all">Đăng xuất</button>
            </div>
          </div>
        )}
      </main>

      {showFab && (
        <div className="fixed bottom-24 right-6 z-40">
          <button onClick={handleFabClick} className="w-14 h-14 rounded-full shadow-fab bg-primary text-white flex items-center justify-center hover:scale-110 active:scale-95 transition-all">
            <span className="material-symbols-outlined text-[32px]">add</span>
          </button>
        </div>
      )}

      <Navigation activeTab={activeTab} setActiveTab={setActiveTab} isAdmin={isAdmin} />
      {isAddDeviceOpen && <AddDeviceModal existingTagIds={existingTagIds} onClose={() => setIsAddDeviceOpen(false)} onSubmit={handleAddDevice} isSaving={isSaving} />}
      {isAddUserOpen && <AddUserModal onClose={() => setIsAddUserOpen(false)} onSubmit={(u) => sendPostRequest({ ...u, action: 'ADD_USER', timestamp: new Date().toISOString(), performedBy: currentUser?.name })} isSaving={isSaving} />}
      {assigningDevice && <AssignUserModal users={users} onClose={() => setAssigningDevice(null)} onSubmit={(u) => sendPostRequest({ action: 'ASSIGN_DEVICE', tagId: assigningDevice.tagId, userName: u.name, timestamp: new Date().toISOString(), performedBy: currentUser?.name })} isSaving={isSaving} />}
      {editingDevice && <EditDeviceModal device={editingDevice} onClose={() => setEditingDevice(null)} onSubmit={handleEditDevice} isSaving={isSaving} />}
      {editingUser && <EditUserModal user={editingUser} onClose={() => setEditingUser(null)} onSubmit={handleEditUser} isSaving={isSaving} />}
      {settingUpDevice && <SetupModal 
        device={settingUpDevice} 
        existingSetup={setups.find(s => s.tagId === settingUpDevice.tagId)} 
        onClose={() => setSettingUpDevice(null)} 
        onSubmit={handleSaveSetup} 
        isSaving={isSaving} 
      />}
    </div>
  );
};

export default App;

import React from 'react';
import { TabType } from '../types';

interface NavigationProps {
  activeTab: TabType;
  setActiveTab: (tab: TabType) => void;
  isAdmin: boolean;
}

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab, isAdmin }) => {
  const tabs: { id: TabType; icon: string; label: string; adminOnly?: boolean }[] = [
    { id: 'dashboard', icon: 'dashboard', label: 'Dashboard' },
    { id: 'devices', icon: 'inventory_2', label: 'Devices' },
    { id: 'users', icon: 'group', label: 'Users' },
    { id: 'setup', icon: 'settings_suggest', label: 'Setup', adminOnly: true },
    { id: 'settings', icon: 'settings', label: 'Settings' },
  ];

  const visibleTabs = tabs.filter(t => !t.adminOnly || isAdmin);

  return (
    <nav className="fixed bottom-0 inset-x-0 h-16 bg-white border-t border-slate-200 flex items-center justify-around px-2 z-40">
      {visibleTabs.map((tab) => (
        <button
          key={tab.id}
          onClick={() => setActiveTab(tab.id)}
          className={`flex flex-col items-center gap-0.5 flex-1 transition-colors ${
            activeTab === tab.id ? 'text-primary' : 'text-slate-400'
          }`}
        >
          <span className={`material-symbols-outlined ${activeTab === tab.id ? 'font-fill' : ''}`}>
            {tab.icon}
          </span>
          <span className={`text-[10px] ${activeTab === tab.id ? 'font-bold' : 'font-medium'}`}>
            {tab.label}
          </span>
        </button>
      ))}
    </nav>
  );
};

export default Navigation;

import React, { useState, useEffect } from 'react';
import { Device, HistoryEntry, AssetStatus } from '../types';
import DeviceCard from './DeviceCard';
import TimelineItem from './TimelineItem';

interface DashboardViewProps {
  devices: Device[];
  history: HistoryEntry[];
  onViewAll: () => void;
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  onDelete: (id: string) => void;
  onSetup: (device: Device) => void;
  isAdmin: boolean;
  isManagement: boolean;
  onSearch: (val: string) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ devices, history, onViewAll, onAction, onEdit, onDelete, onSetup, isAdmin, isManagement, onSearch }) => {
  const [localSearch, setLocalSearch] = useState('');
  const [greeting, setGreeting] = useState('');
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const hour = currentTime.getHours();
    if (hour < 12) setGreeting('Chào buổi sáng');
    else if (hour < 18) setGreeting('Chào buổi chiều');
    else setGreeting('Chào buổi tối');

    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const formatDate = (date: Date) => {
    const days = ['Chủ Nhật', 'Thứ Hai', 'Thứ Ba', 'Thứ Tư', 'Thứ Năm', 'Thứ Sáu', 'Thứ Bảy'];
    const d = days[date.getDay()];
    const day = date.getDate().toString().padStart(2, '0');
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const year = date.getFullYear();
    return `${d}, ${day}/${month}/${year}`;
  };

  const formatTime = (date: Date) => {
    const hours = date.getHours().toString().padStart(2, '0');
    const mins = date.getMinutes().toString().padStart(2, '0');
    const secs = date.getSeconds().toString().padStart(2, '0');
    return { hours, mins, secs };
  };

  const time = formatTime(currentTime);

  const stats = {
    total: devices.length,
    available: devices.filter(d => d.status === 'AVAILABLE').length,
    assigned: devices.filter(d => d.status === 'ASSIGNED').length,
    pending: devices.filter(d => d.status === 'PENDING').length,
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <section className="relative overflow-hidden bg-gradient-to-br from-primary to-blue-700 rounded-[40px] p-6 text-white shadow-2xl">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-10 -left-10 w-32 h-32 bg-blue-400/20 rounded-full blur-2xl"></div>

        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
          <div>
            <h1 className="text-3xl font-black mb-1">{greeting}!</h1>
            <p className="text-blue-100 text-sm opacity-90 font-medium">Hệ thống đang phục vụ {isManagement ? 'điều hành' : 'tra cứu'}.</p>
          </div>

          <div className="flex items-center gap-4 bg-white/10 backdrop-blur-md border border-white/20 rounded-3xl p-4 pr-6">
            <div className="bg-white/20 w-12 h-12 rounded-2xl flex items-center justify-center">
              <span className="material-symbols-outlined text-white text-[28px]">calendar_month</span>
            </div>
            <div className="flex flex-col">
              <div className="flex items-baseline gap-1">
                <span className="text-2xl font-black tracking-tight">{time.hours}</span>
                <span className="text-xl font-bold opacity-50 animate-pulse">:</span>
                <span className="text-2xl font-black tracking-tight">{time.mins}</span>
                <span className="text-sm font-bold opacity-60 ml-1">{time.secs}</span>
              </div>
              <span className="text-[10px] font-bold uppercase tracking-wider opacity-80">{formatDate(currentTime)}</span>
            </div>
          </div>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); onSearch(localSearch); }} className="relative z-10">
          <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-primary">search</span>
          <input 
            type="text" 
            placeholder="Tìm: Tên, mã, trạng thái (Sẵn sàng...)"
            className="w-full bg-white rounded-2xl py-4 pl-12 pr-4 text-sm text-slate-800 border-none focus:ring-4 focus:ring-white/20 transition-all shadow-xl"
            value={localSearch}
            onChange={e => setLocalSearch(e.target.value)}
          />
        </form>
      </section>

      <section>
        <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-4 px-1">{isManagement ? 'Chỉ số hệ thống' : 'Tài sản cá nhân'}</h2>
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard icon="inventory_2" label="Tổng tài sản" value={stats.total} color="bg-blue-50 text-blue-600" />
          <StatCard icon="verified" label="Sẵn sàng" value={stats.available} color="bg-green-50 text-green-600" onClick={() => onSearch('Sẵn sàng')} />
          <StatCard icon="assignment_ind" label="Đang cấp" value={stats.assigned} color="bg-red-50 text-red-600" onClick={() => onSearch('Đang sử dụng')} />
          <StatCard icon="hourglass_empty" label="Đang chờ" value={stats.pending} color="bg-orange-50 text-orange-600" onClick={() => onSearch('Chờ duyệt')} />
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <section>
          <div className="flex items-center justify-between mb-4 px-1">
            <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Thiết bị tiêu biểu</h2>
            <button onClick={onViewAll} className="text-primary text-xs font-bold">Xem tất cả</button>
          </div>
          <div className="space-y-4">
            {devices.slice(0, 3).map(device => (
              <DeviceCard key={device.id} device={device} onAction={onAction} onEdit={onEdit} onDelete={onDelete} onSetup={onSetup} isAdmin={isAdmin} isManagement={isManagement} />
            ))}
          </div>
        </section>
        <section>
          <h2 className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mb-4">Nhật ký mới nhất</h2>
          <div className="space-y-6">
            {history.slice(0, 5).map(entry => <TimelineItem key={entry.id} entry={entry} />)}
          </div>
        </section>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ icon: string; label: string; value: number; color: string; onClick?: () => void }> = ({ icon, label, value, color, onClick }) => (
  <div 
    onClick={onClick}
    className={`bg-white p-5 rounded-3xl shadow-subtle border border-slate-100 flex items-center gap-4 transition-all ${onClick ? 'cursor-pointer hover:border-primary/30 hover:shadow-lg active:scale-95' : ''}`}
  >
    <div className={`w-12 h-12 rounded-2xl ${color.split(' ')[0]} flex items-center justify-center`}>
      <span className={`material-symbols-outlined ${color.split(' ')[1]}`}>{icon}</span>
    </div>
    <div>
      <div className="text-2xl font-black text-slate-800 leading-none mb-1">{value}</div>
      <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">{label}</div>
    </div>
  </div>
);

export default DashboardView;

import React, { useState } from 'react';
import { Device, AssetStatus } from '../types';

interface DeviceCardProps {
  device: Device;
  onAction: (id: string, action: 'ASSIGN' | 'RETURN') => void;
  onEdit: (device: Device) => void;
  onDelete: (id: string) => void;
  onSetup: (device: Device) => void;
  isAdmin: boolean;
  isManagement: boolean;
}

const DeviceCard: React.FC<DeviceCardProps> = ({ device, onAction, onEdit, onDelete, onSetup, isAdmin, isManagement }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const isAssigned = device.status === 'ASSIGNED';
  const isAvailable = device.status === 'AVAILABLE';

  const getStatusStyles = (status: AssetStatus) => {
    switch (status) {
      case 'AVAILABLE': return 'bg-green-50 text-status-available';
      case 'ASSIGNED': return 'bg-red-50 text-status-assigned';
      case 'PENDING': return 'bg-orange-50 text-status-pending';
      case 'REPAIR': return 'bg-amber-50 text-amber-600';
      default: return 'bg-slate-50 text-slate-500';
    }
  };

  const getStatusLabel = (status: AssetStatus) => {
    switch (status) {
      case 'AVAILABLE': return 'Sẵn sàng';
      case 'ASSIGNED': return 'Đang sử dụng';
      case 'PENDING': return 'Chờ duyệt';
      case 'REPAIR': return 'Sửa chữa';
      default: return status;
    }
  };

  const formatDateTime = (isoString: string) => {
    if (!isoString) return 'N/A';
    try {
      const date = new Date(isoString);
      if (isNaN(date.getTime())) return isoString;

      return new Intl.DateTimeFormat('vi-VN', {
        hour: '2-digit',
        minute: '2-digit',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
      }).format(date);
    } catch (e) {
      return isoString;
    }
  };

  return (
    <div onClick={() => setIsExpanded(!isExpanded)} className={`bg-white rounded-2xl border border-slate-100 shadow-subtle overflow-hidden flex flex-col transition-all cursor-pointer ${isExpanded ? 'ring-2 ring-primary/20' : ''}`}>
      <div className="p-4">
        <div className="flex justify-between items-start mb-3">
          <div className="flex-1 min-w-0 pr-2">
            <h3 className="font-bold text-slate-800 text-base truncate">{device.name}</h3>
            <p className="text-xs text-slate-400">ID: {device.tagId} • <span className="text-primary font-bold uppercase">{device.type}</span></p>
          </div>
          <span className={`text-[10px] px-2.5 py-1 rounded-full font-bold uppercase ${getStatusStyles(device.status)}`}>{getStatusLabel(device.status)}</span>
        </div>

        {isAssigned && device.assignedTo && (
          <div className="mb-3 px-3 py-2 bg-red-50/50 rounded-xl border border-red-100 flex items-center gap-2">
            <span className="material-symbols-outlined text-[16px] text-red-500">person</span>
            <span className="text-xs font-bold text-red-700 truncate">Sử dụng: {device.assignedTo}</span>
          </div>
        )}

        <div className="space-y-2">
          <div className="flex items-center gap-2 text-xs text-slate-600">
             <span className="material-symbols-outlined text-[16px] text-slate-400">settings_input_component</span>
             <span className="truncate">{device.configuration || 'N/A'}</span>
          </div>
          <div className="flex items-center gap-2 text-xs text-slate-600">
             <span className="material-symbols-outlined text-[16px] text-slate-400">location_on</span>
             <span>{device.location}</span>
          </div>
        </div>

        {isExpanded && (
          <div className="mt-4 pt-4 border-t border-slate-50 space-y-2 animate-fadeIn">
            <p className="text-xs text-slate-500"><b>Phụ kiện:</b> {device.accessory || 'Không'}</p>
            <p className="text-xs text-slate-500"><b>Ghi chú:</b> {device.note || 'Trống'}</p>
            <div className="flex items-center gap-1.5 pt-1">
              <span className="material-symbols-outlined text-[14px] text-slate-400">update</span>
              <p className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Cập nhật: {formatDateTime(device.lastUpdated)}</p>
            </div>
          </div>
        )}
      </div>

      {isManagement ? (
        <div onClick={(e) => e.stopPropagation()} className="border-t border-slate-50 p-3 bg-slate-50/30 flex flex-wrap gap-2">
          {isAdmin && (
            <button onClick={() => onEdit(device)} className="flex-1 min-w-[70px] bg-white border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-600 flex items-center justify-center gap-1 hover:bg-slate-50">
              <span className="material-symbols-outlined text-[16px]">edit</span> Sửa
            </button>
          )}

          <button onClick={() => onSetup(device)} className="flex-1 min-w-[70px] bg-white border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-600 flex items-center justify-center gap-1 hover:bg-slate-50">
            <span className="material-symbols-outlined text-[16px]">settings_suggest</span> Setup
          </button>

          {isAssigned ? (
            <button onClick={() => onAction(device.id, 'RETURN')} className="flex-1 min-w-[70px] bg-white border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-600 flex items-center justify-center gap-1 hover:bg-slate-50">
              <span className="material-symbols-outlined text-[16px]">keyboard_return</span> Thu hồi
            </button>
          ) : isAvailable ? (
            <button onClick={() => onAction(device.id, 'ASSIGN')} className="flex-1 min-w-[70px] bg-primary text-white py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-1 hover:bg-blue-600">
              <span className="material-symbols-outlined text-[16px]">person_add</span> Cấp phát
            </button>
          ) : (
            <div className="flex-1 min-w-[70px] bg-slate-100 border border-slate-200 py-2 rounded-lg text-xs font-bold text-slate-400 flex items-center justify-center gap-1 cursor-not-allowed">
              <span className="material-symbols-outlined text-[16px]">lock</span> {device.status === 'PENDING' ? 'Chờ' : 'Sửa'}
            </div>
          )}

          {isAdmin && (device.status === 'PENDING' || device.status === 'AVAILABLE') && (
            <button onClick={() => onDelete(device.id)} className="w-10 h-10 bg-white border border-red-100 rounded-lg text-red-500 flex items-center justify-center hover:bg-red-500 hover:text-white transition-all">
              <span className="material-symbols-outlined text-[20px]">delete</span>
            </button>
          )}
        </div>
      ) : (
        <div className="border-t border-slate-50 p-2.5 bg-slate-50/10 flex justify-center italic text-[10px] text-slate-400 uppercase font-bold">
           View Only
        </div>
      )}
    </div>
  );
};

